const sites = [
  {id:'great-blue-hole',name:'大蓝洞',en:'Great Blue Hole · Belize',lat:17.3156,lng:-87.5346,depth:'5–40 m',species:'加勒比礁鲨、护士鲨',terrain:'海洋天坑、钟乳石',level:'进阶',rating:3,season:'4–6月',visibility:'20–30 m',temp:'26–29°C',desc:'伯利兹灯塔礁中央的巨大海洋天坑。水面像一枚深蓝瞳孔，30米以下的钟乳石与内凹岩壁构成近乎超现实的空间。这里的重点是地质景观而非珊瑚密度，深度与减压压力需要被认真对待。',facts:['经典路线沿内壁下潜，在约30–40米观察巨型钟乳石','洞口偶见加勒比礁鲨与护士鲨，浅层礁盘适合放松潜','深处光线快速减弱，不建议缺乏深潜经验的潜水员追深'],route:'通常由圣佩德罗或普拉森西亚出发，快艇航程较长；建议选择包含邻近浅礁的两至三潜行程。',safety:'建议具备 AOW 与近期深潜经验。严格遵守免减压时间，保持与导潜同深度，不进入未经训练的顶置空间。'},
  {id:'galapagos',name:'加拉帕戈斯',en:'Darwin & Wolf · Ecuador',lat:1.67,lng:-91.99,depth:'8–35 m',species:'锤头鲨、鲸鲨、海鬣蜥',terrain:'火山岩壁、强流',level:'专家',rating:2,season:'6–11月',visibility:'10–30 m',temp:'18–27°C',desc:'多股洋流在火山群岛周围交汇，造就地球上最具野性的远洋潜水之一。锤头鲨群、鲸鲨、海狮和鹰鳐可能在同一趟旅程出现，但低温、浪涌与不可预测的强流也让它只适合经验充足者。',facts:['达尔文与沃尔夫岛是锤头鲨群和鲸鲨的核心区域','伊莎贝拉岛可观察海鬣蜥入水觅食的罕见行为','水温分层明显，同一潜次可能经历大幅温差'],route:'远海核心潜点通常只能通过7晚以上船宿抵达；陆基行程更适合探索中部岛屿与海狮、海鬣蜥主题潜点。',safety:'建议至少50潜并熟悉负浮力入水、强流和低能见度。携带象拔、鸣笛与个人定位设备。'},
  {id:'red-sea',name:'红海北部',en:'Northern Red Sea · Egypt',lat:27.83,lng:34.26,depth:'5–30 m',species:'海豚、苏眉鱼、礁鲨',terrain:'珊瑚峭壁、历史沉船',level:'新手友好',rating:5,season:'3–5月 / 9–11月',visibility:'25–40 m',temp:'22–29°C',desc:'清澈温暖的海水、保存良好的珊瑚峭壁与世界级沉船集中在相对紧凑的海域。既能安排平静浅礁教学，也能进入 SS Thistlegorm 的历史现场，是从初学到技术潜水都能找到路线的目的地。',facts:['Ras Mohammed 的礁角常形成杰克鱼与笛鲷鱼群','SS Thistlegorm 保留摩托车、卡车等二战时期货物','沙姆沙伊赫周边兼具岸潜、日船与船宿选择'],route:'首次到访可选沙姆沙伊赫日船；想集中探索沉船与离岸礁群，北线船宿效率最高。',safety:'沉船穿越需要专门训练与可靠照明。冬季出水后风寒明显；礁角可能出现下降流。'},
  {id:'maldives',name:'马尔代夫',en:'Central Atolls · Maldives',lat:3.2,lng:73.22,depth:'5–30 m',species:'蝠鲼、鲸鲨、礁鲨',terrain:'环礁水道、海山',level:'中级',rating:4,season:'1–4月',visibility:'15–30 m',temp:'27–30°C',desc:'环礁水道把印度洋的营养与远洋生物带到礁盘边缘。潜水节奏由潮汐决定：在清洁站静候蝠鲼，在水道入口观察鲨鱼，或沿海山顺流穿过密集鱼群。',facts:['Ari Atoll 南部全年有机会遇见鲸鲨','北马累环礁拥有成熟的蝠鲼清洁站潜点','水道潜水的体验会随进流、出流发生显著变化'],route:'度假村适合轻松、定点探索；船宿可跨越多个环礁并依据潮汐灵活调整路线。',safety:'水道流速可能很快，必须掌握流潜和放象拔。不要追逐蝠鲼或鲸鲨，遵循清洁站观察距离。'},
  {id:'sipadan',name:'诗巴丹',en:'Sipadan · Malaysia',lat:4.114,lng:118.628,depth:'5–40 m',species:'海龟、梭鱼、杰克鱼',terrain:'火山岛峭壁',level:'中级',rating:4,season:'4–12月',visibility:'15–35 m',temp:'27–30°C',desc:'一座从六百米深海拔起的海洋岛，离岸数米便是垂直峭壁。梭鱼风暴、杰克鱼旋涡和密集海龟构成标志性场景，单位水体里的生命密度令人目不暇接。',facts:['Barracuda Point 的梭鱼群可形成巨大银色旋涡','Turtle Cavern 洞穴系统只适合受训洞潜者','严格的每日许可制度保护了潜点承载力'],route:'住在马布岛或卡帕莱，通过持牌潜店抽取诗巴丹名额；建议预留数日提高获得许可的机会。',safety:'峭壁外侧可能有强流。普通休闲潜水员不可进入海龟洞，出发前确认潜店是否拥有当日有效许可。'},
  {id:'raja-ampat',name:'四王群岛',en:'Raja Ampat · Indonesia',lat:-0.45,lng:130.7,depth:'3–30 m',species:'侏儒海马、蝠鲼、须鲨',terrain:'珊瑚花园、海山、水道',level:'全级别',rating:5,season:'10–4月',visibility:'10–30 m',temp:'27–30°C',desc:'位于珊瑚大三角核心的海洋生物多样性高地。海扇、软珊瑚与硬珊瑚层层叠叠，从微小的侏儒海马到远洋蝠鲼都能成为一潜的主角。',facts:['区域记录超过1500种珊瑚礁鱼类','Cape Kri 以惊人的单潜鱼种数量闻名','Misool 的软珊瑚景观与海扇森林尤其出色'],route:'北部 Dampier Strait 交通较便利；船宿能覆盖 Misool 与偏远海域，适合10天左右的完整行程。',safety:'部分水道流速很快且潮汐窗口短。保护娇嫩珊瑚，不佩戴手套，不触碰海扇寻找微距生物。'},
  {id:'great-barrier-reef',name:'大堡礁',en:'Great Barrier Reef · Australia',lat:-18.29,lng:147.7,depth:'5–30 m',species:'海龟、小丑鱼、鳕鱼',terrain:'堡礁、珊瑚花园',level:'新手友好',rating:5,season:'6–10月',visibility:'10–30 m',temp:'23–29°C',desc:'全球规模最大的珊瑚礁生态系统拥有从平静浅礁到远海峭壁的巨大选择。凯恩斯近海适合初体验，Ribbon Reefs 和 Osprey Reef 则为经验潜水员提供更清澈、更丰富的远海景观。',facts:['Cod Hole 可近距离观察体型巨大的马铃薯鳕','冬季远海有机会遇见小须鲸','不同纬度、离岸距离与季节造成显著不同的生态体验'],route:'时间有限可参加凯恩斯或道格拉斯港日船；3–7晚船宿能到达人少、状态更佳的外堡礁。',safety:'注意热带日晒、脱水与船程晕浪。珊瑚礁跨度极大，应依据实时白化与天气信息选择具体区域。'},
  {id:'palau',name:'帕劳蓝角',en:'Blue Corner · Palau',lat:7.13,lng:134.22,depth:'8–30 m',species:'灰礁鲨、拿破仑鱼',terrain:'垂直峭壁、强流礁角',level:'进阶',rating:3,season:'11–5月',visibility:'20–40 m',temp:'27–30°C',desc:'帕劳最具代表性的礁角潜水。潜水员使用流钩停留在礁盘边缘，观看灰礁鲨、金枪鱼、杰克鱼和拿破仑鱼在蓝水中巡游，像坐在海底剧院第一排。',facts:['流向合适时，礁角会聚集大量远洋生物','邻近德国水道是蝠鲼清洁站热点','帕劳同时拥有蓝洞、沉船与水母湖等多样体验'],route:'科罗尔日船可覆盖主要潜点；船宿减少每日往返时间，更容易抓住最佳潮汐窗口。',safety:'必须熟练使用流钩且不可挂在活珊瑚上。礁角外侧流况复杂，跟紧导潜并携带个人定位装备。'},
  {id:'komodo',name:'科莫多',en:'Komodo National Park · Indonesia',lat:-8.57,lng:119.58,depth:'5–35 m',species:'蝠鲼、礁鲨、海蛞蝓',terrain:'海山、峡道、强流',level:'进阶',rating:3,season:'4–11月',visibility:'10–30 m',temp:'22–29°C',desc:'太平洋与印度洋水团在狭窄岛链间交换，制造出高速水流和爆发式生命。北部以清澈暖水与鱼群见长，南部则是冷水、软珊瑚和微距生物的世界。',facts:['Manta Alley 与 Mawan 是稳定的蝠鲼观察点','Castle Rock 的海山常有鲨鱼与金枪鱼巡游','南北水温差可超过5°C，生态面貌截然不同'],route:'拉布安巴焦日船可到中北部；4–7晚船宿更适合同时覆盖南部与北部。',safety:'钩流、下降流与洗衣机流并存，行程应匹配经验。准备不同厚度防寒衣并严格听从潮汐简报。'},
  {id:'tubbataha',name:'图巴塔哈礁',en:'Tubbataha Reefs · Philippines',lat:8.95,lng:119.87,depth:'5–40 m',species:'鲸鲨、礁鲨、海龟',terrain:'远海环礁、峭壁',level:'进阶',rating:3,season:'3–6月',visibility:'20–45 m',temp:'27–30°C',desc:'苏禄海中央的两座远海环礁，是菲律宾保存最完整的海洋保护区之一。垂直礁壁、健康珊瑚和大型远洋生物是主角，只有短暂平静季节能够抵达。',facts:['联合国世界遗产级海洋保护区','常见白鳍礁鲨、灰礁鲨与大群杰克鱼','偏远位置让珊瑚覆盖与鱼类密度保持高水平'],route:'只能从公主港搭乘约一周船宿抵达，船位通常需提前数月预订。',safety:'远离陆地且医疗撤离困难，建议购买覆盖潜水撤离的保险；保持保守潜水曲线。'},
  {id:'fiji',name:'斐济彩虹礁',en:'Rainbow Reef · Fiji',lat:-16.75,lng:179.79,depth:'5–30 m',species:'软珊瑚、礁鲨、海龟',terrain:'软珊瑚墙、水道',level:'中级',rating:4,season:'5–10月',visibility:'15–40 m',temp:'25–29°C',desc:'Somosomo 海峡的水流为礁壁输送营养，让软珊瑚在流起时完全绽放。白墙与彩虹礁以强烈色彩和层次感闻名，是广角摄影师钟爱的水下花园。',facts:['Great White Wall 覆盖大片白色软珊瑚','流起时软珊瑚舒展，景观最为饱满','邻近礁区可见成群梭鱼、海龟与礁鲨'],route:'住在塔韦乌尼岛可日船探索；选潜店时确认其是否依据潮汐安排白墙潜次。',safety:'最佳观赏状态往往伴随水流，需要可靠的中性浮力与贴近礁壁的能力。'},
  {id:'bonaire',name:'博奈尔岛',en:'Bonaire · Caribbean Netherlands',lat:12.18,lng:-68.26,depth:'3–35 m',species:'海龟、鹰鳐、海马',terrain:'缓坡礁、岸潜',level:'新手友好',rating:5,season:'全年',visibility:'20–35 m',temp:'26–29°C',desc:'全球岸潜自由度最高的目的地之一。黄色路标标出数十个入水点，平静背风海岸、清晰导航和由浅入深的礁坡非常适合新手、摄影师和自主潜伴。',facts:['可租车携气瓶自行规划一日多潜','Salt Pier 的桥墩形成独特光影与鱼群景观','海洋公园制度长期保护近岸珊瑚礁'],route:'完成当地潜店的浮力与海洋公园检查后，租用皮卡沿西岸探索；东岸建议跟随当地向导。',safety:'岸潜需评估碎石入水、浪况和停车安全；必须使用潜伴制度并留意返程气量。'},
  {id:'cozumel',name:'科苏梅尔',en:'Cozumel · Mexico',lat:20.37,lng:-86.94,depth:'8–35 m',species:'玳瑁、鹰鳐、蟾鱼',terrain:'珊瑚墙、漂流潜水',level:'中级',rating:4,season:'11–4月',visibility:'25–40 m',temp:'26–29°C',desc:'墨西哥加勒比海的经典漂流潜水地。稳定洋流带着潜水员掠过高耸珊瑚塔和深蓝峭壁，能见度优异，特有的华丽蟾鱼藏在礁石底部。',facts:['Palancar Reef 拥有峡谷般的珊瑚塔结构','哥伦比亚墙沿深蓝海域垂直下降','冬季常见鹰鳐在沙地与礁坡巡游'],route:'多数行程为上午两潜快船；住在岛上比从坎昆当天往返更从容。',safety:'漂流潜水须与同组保持一致深度，走散后按程序上升并放象拔；码头船流繁忙。'},
  {id:'socorro',name:'索科罗群岛',en:'Revillagigedo · Mexico',lat:18.78,lng:-110.95,depth:'8–35 m',species:'巨型蝠鲼、海豚、锤头鲨',terrain:'远海火山岛、海山',level:'专家',rating:2,season:'11–5月',visibility:'10–30 m',temp:'21–28°C',desc:'东太平洋的远海巨物目的地，以主动接近潜水员的巨型太平洋蝠鲼闻名。海豚、锤头鲨、虎鲨与座头鲸让每一潜都带有未知感。',facts:['San Benedicto 的 Boiler 是巨型蝠鲼代表潜点','Roca Partida 是露出水面的孤立火山岩柱','冬末可在水下听到座头鲸歌声'],route:'从卡波圣卢卡斯出发，船宿通常9–11晚，首尾均有长距离航行。',safety:'远海浪况、负浮力入水和强流对体能要求高；建议至少50潜并使用个人定位信标。'},
  {id:'cocos',name:'科科斯岛',en:'Cocos Island · Costa Rica',lat:5.53,lng:-87.06,depth:'10–40 m',species:'锤头鲨、白鳍鲨、鹰鳐',terrain:'海山、岩礁、强流',level:'专家',rating:2,season:'6–11月',visibility:'10–30 m',temp:'24–29°C',desc:'离哥斯达黎加大陆约550公里的雨林岛屿，被称为鲨鱼潜水圣地。清洁站周围的锤头鲨群、密集白鳍鲨和大型鱼群构成纯粹的远洋生态。',facts:['Bajo Alcyone 海山是锤头鲨群标志潜点','夜潜可见大量白鳍鲨协同捕猎','岛屿降雨丰沛，瀑布直接落入海湾'],route:'只能通过10天左右船宿到达，单程航行约30多小时。',safety:'环境偏远、流强且常有低能见度。需要高级证书、丰富船潜经验与覆盖高额撤离费用的保险。'},
  {id:'silfra',name:'丝浮拉裂缝',en:'Silfra · Iceland',lat:64.255,lng:-21.13,depth:'2–18 m',species:'地质景观、极清淡水',terrain:'板块裂缝、熔岩岩壁',level:'中级',rating:3,season:'全年',visibility:'80–100 m',temp:'2–4°C',desc:'北美与欧亚板块之间的清澈淡水裂缝。经过熔岩过滤的冰川水带来近乎无限的能见度，蓝色光线、岩壁纹理和失重感取代大型海洋生物成为主角。',facts:['水体能见度可超过80米','可在狭窄处同时触及两侧板块岩壁','全年水温接近冰点但水流较温和'],route:'从雷克雅未克参加半日或一日活动；潜水必须由许可运营商组织，浮潜门槛较低。',safety:'干衣潜水经验至关重要，手部保温与配重需要精确调整；遵守当地最低证书与近期干衣潜水要求。'},
  {id:'poor-knights',name:'穷骑士群岛',en:'Poor Knights · New Zealand',lat:-35.48,lng:174.74,depth:'5–40 m',species:'黄貂鱼、海鳗、海藻鱼',terrain:'海蚀洞、拱门、峭壁',level:'全级别',rating:4,season:'1–5月',visibility:'15–30 m',temp:'15–22°C',desc:'亚热带洋流围绕火山岛形成独特生态，巨型海蚀洞、蓝色拱门与茂密海藻林交错。温带和亚热带物种在这里相遇，地形探索感极强。',facts:['Rikoriko Cave 是世界大型海蚀洞之一','拱门与垂直岩壁为广角摄影提供丰富构图','季节性可见短尾黄貂鱼聚集'],route:'从图图卡卡搭乘日船，航程约一小时；多数船提供两潜并依据海况选择岛屿两侧。',safety:'水温较低且天气变化快，准备合适防寒衣；洞穴路线保持自然光出口，不越过休闲潜水界限。'},
  {id:'aliwal',name:'阿里瓦尔浅滩',en:'Aliwal Shoal · South Africa',lat:-30.26,lng:30.82,depth:'5–35 m',species:'沙虎鲨、虎鲨、海豚',terrain:'砂岩礁、沉船',level:'进阶',rating:3,season:'6–11月',visibility:'5–25 m',temp:'19–26°C',desc:'南非夸祖鲁-纳塔尔近岸的砂岩礁，以无笼鲨鱼潜水与季节性沙虎鲨聚集闻名。快速橡皮艇出海、海滩冲浪区入水和多变能见度让旅程充满运动感。',facts:['冬季洞穴和沟槽中常见沙虎鲨','外海饵潜有机会观察黑鳍鲨与虎鲨','Produce 沉船覆盖珊瑚并聚集大型石斑鱼'],route:'从 Umkomaas 出发，通常乘硬底充气艇穿越浪区；预留天气取消的弹性天数。',safety:'需熟悉负浮力入水和船边快速集合。鲨潜严格遵守运营商程序，不触碰、不追逐动物。'},
  {id:'brothers',name:'兄弟岛',en:'The Brothers · Egypt',lat:26.31,lng:34.85,depth:'10–40 m',species:'长尾鲨、锤头鲨、灰礁鲨',terrain:'远海峭壁、沉船',level:'专家',rating:2,season:'春季与秋季',visibility:'20–40 m',temp:'23–29°C',desc:'红海中央两座孤立小岛从深海陡然升起，是长尾鲨、锤头鲨和沉船爱好者的交会点。珊瑚覆盖的峭壁直接落入蓝水，环境比北部红海更具挑战。',facts:['清晨有机会观察长尾鲨在礁角巡游','Numidia 与 Aida 沉船附着大量软珊瑚','岛屿孤立位置吸引多种远洋鲨鱼'],route:'仅通过埃及红海南部船宿抵达，常与 Daedalus、Elphinstone 组成 BDE 路线。',safety:'强流、深水与远海环境要求丰富经验；遵守当地对最低潜水次数的规定，携带象拔和定位设备。'},
  {id:'okinawa',name:'冲绳庆良间',en:'Kerama Islands · Japan',lat:26.2,lng:127.35,depth:'5–30 m',species:'座头鲸、海龟、花园鳗',terrain:'白沙地、珊瑚礁、海峡',level:'新手友好',rating:5,season:'4–11月',visibility:'20–40 m',temp:'21–29°C',desc:'透明度极高的“庆良间蓝”包围着白沙地、桌状珊瑚和层次清楚的礁坡。海龟频繁出现，平静潜点适合新手，外侧水道也为进阶者提供流潜体验。',facts:['阿嘉岛与座间味岛周边海龟出现率高','冬季是座头鲸繁殖季，可结合观鲸活动','清澈白沙地非常适合练习中性浮力与摄影'],route:'可从那霸参加日船，也可住在庆良间诸岛享受更慢节奏与较短船程。',safety:'台风季需关注停航信息；冬季水温明显下降。部分水道有快速潮流，应依证书选择潜点。'},
  {id:'yonaguni',name:'与那国岛',en:'Yonaguni · Japan',lat:24.45,lng:123.01,depth:'8–35 m',species:'锤头鲨、海龟',terrain:'海底遗迹、峭壁、强流',level:'专家',rating:2,season:'12–3月',visibility:'15–35 m',temp:'22–29°C',desc:'日本最西端的远海岛屿，以冬季锤头鲨群和充满争议的海底地形闻名。阶梯、平台与直角岩壁极具建筑感，外海蓝水潜水则充满速度与未知。',facts:['冬季蓝水中有机会遇见成群锤头鲨','海底遗迹拥有巨型台阶、沟槽与平台','所有潜次均高度依赖风浪和潮流窗口'],route:'从石垣岛转机或乘船抵达，建议至少停留四晚，为天气取消预留弹性。',safety:'多为负浮力入水和无参照蓝水潜水，仅适合熟悉强流、快速下潜与放象拔的潜水员。'},
  {id:'apo-reef',name:'阿波礁',en:'Apo Reef · Philippines',lat:12.67,lng:120.42,depth:'5–35 m',species:'礁鲨、海龟、蝠鲼',terrain:'远海环礁、峭壁',level:'中级',rating:4,season:'3–5月',visibility:'20–40 m',temp:'27–30°C',desc:'菲律宾最大的连续珊瑚礁系统之一，远离城市的环礁拥有清澈蓝水、陡峭外墙和大面积浅水珊瑚花园，氛围比热门海岛更安静。',facts:['外礁墙常见白鳍礁鲨与鹰鳐','浅礁适合观察海龟和密集珊瑚鱼','环礁灯塔周边拥有开阔潟湖景观'],route:'通常从民都洛岛西岸乘船前往，可选择一日长线或在礁区过夜的船宿。',safety:'航程长且海况变化快；外墙可能有下降流，应保持与礁壁的安全距离。'},
  {id:'lembeh',name:'蓝碧海峡',en:'Lembeh Strait · Indonesia',lat:1.46,lng:125.24,depth:'3–25 m',species:'蓝环章鱼、拟态章鱼、躄鱼',terrain:'黑沙、碎石坡、微距生态',level:'全级别',rating:5,season:'全年',visibility:'5–15 m',temp:'26–29°C',desc:'世界级黑沙微距潜水圣地。看似朴素的火山沙坡藏着拟态章鱼、蓝环章鱼、毛躄鱼与无数奇特小生物，体验如同缓慢的水下寻宝。',facts:['生物密度高，适合微距摄影与观察','不同沙坡对应不同伪装物种组合','经验丰富的当地向导是发现目标的关键'],route:'住在海峡两岸的潜水度假村最方便，建议安排至少四个潜水日覆盖不同微距主题。',safety:'控制蛙踢避免扬沙和伤害小生物；蓝环章鱼等物种有毒，绝不触碰。'},
  {id:'moalboal',name:'墨宝沙丁鱼风暴',en:'Moalboal · Philippines',lat:9.95,lng:123.37,depth:'3–30 m',species:'沙丁鱼、海龟、长尾鲨',terrain:'近岸峭壁、鱼群',level:'新手友好',rating:5,season:'全年',visibility:'10–25 m',temp:'27–30°C',desc:'数以百万计的沙丁鱼常年聚集在帕纳萨马海滩外，离岸几分钟便能进入不断变形的银色鱼群。阳光、掠食者和潜水员共同塑造瞬息万变的画面。',facts:['沙丁鱼群距离岸边极近，浮潜也可观察','海龟常在浅水海草床与礁坡活动','Pescador Island 提供洞穴与峭壁潜水'],route:'住在帕纳萨马可随时岸潜；清晨光线柔和、游客较少，是观察鱼群的理想时段。',safety:'鱼群附近船只和自由潜者较多，升水前必须观察水面并使用象拔。'},
  {id:'medes',name:'梅德斯群岛',en:'Medes Islands · Spain',lat:42.05,lng:3.22,depth:'5–40 m',species:'巨型石斑鱼、海鳗、梭鱼',terrain:'石灰岩洞、峭壁、海草床',level:'全级别',rating:4,season:'5–10月',visibility:'10–30 m',temp:'13–24°C',desc:'西地中海管理成熟的海洋保护区。大型石斑鱼毫不畏人，海鳗、梭鱼和红珊瑚分布在洞穴与岩壁间，是欧洲生态恢复的代表潜点。',facts:['长期保护使巨型石斑鱼数量显著恢复','La Vaca 洞穴拥有多个自然光出口','海草床是幼鱼、章鱼和海马的重要栖息地'],route:'从 L’Estartit 港口乘船约十分钟，旺季名额有限，建议提前预约保护区潜次。',safety:'洞穴路线应保持自然光出口；春季水温较低，需选择半干衣或干衣。'},
  {id:'gozo',name:'戈佐岛蓝洞',en:'Gozo · Malta',lat:36.05,lng:14.19,depth:'5–45 m',species:'章鱼、海鳗、海兔',terrain:'拱门、烟囱、洞穴',level:'中级',rating:4,season:'5–10月',visibility:'25–40 m',temp:'15–27°C',desc:'蜂蜜色石灰岩岛屿之下分布着蓝洞、拱门、烟囱与深水隧道。地中海清澈光线穿过岩石开口，创造极具戏剧性的蓝色剪影。',facts:['Blue Hole 从天然岩池进入外海峭壁','Inland Sea 隧道连接潟湖与开放海域','Reqqa Point 适合观察大型鱼群与岩壁'],route:'以岸潜为主，潜店用车辆运送装备；连续数日可根据风向切换岛屿两侧。',safety:'岸边岩石湿滑且步行距离较长；深水地形容易诱发追深，务必设定最大深度。'},
  {id:'azores',name:'亚速尔群岛',en:'Azores · Portugal',lat:38.52,lng:-28.63,depth:'5–40 m',species:'蓝鲨、蝠鲼、鲸豚',terrain:'火山海山、峭壁',level:'进阶',rating:3,season:'6–10月',visibility:'15–40 m',temp:'17–24°C',desc:'大西洋中央的火山群岛是鲸豚迁徙与远洋生物的交汇点。近岸熔岩地形、多鱼海山以及离岸蓝鲨潜水，让行程兼具地形与大型动物主题。',facts:['Princess Alice Bank 夏季可聚集大西洋蝠鲼','皮库岛外海可参加受控蓝鲨潜水','火山拱门与黑色熔岩墙形成鲜明地貌'],route:'皮库适合鲨鱼与鲸豚，法亚尔便于前往远海海山，可按主题组合岛屿。',safety:'远海水面可能粗糙且水温偏低。鲨潜遵从运营商程序，海山潜次携带定位设备。'},
  {id:'grand-cayman',name:'大开曼岛',en:'Grand Cayman · Cayman Islands',lat:19.32,lng:-81.24,depth:'3–40 m',species:'黄貂鱼、海龟、鹰鳐',terrain:'珊瑚墙、沙地、沉船',level:'新手友好',rating:5,season:'全年',visibility:'25–40 m',temp:'26–29°C',desc:'平静海况、卓越能见度和成熟服务使大开曼成为轻松的加勒比潜水目的地。西岸珊瑚墙适合各级别，Stingray City 则以浅水黄貂鱼闻名。',facts:['North Wall 从礁盘边缘垂直落入深蓝','Kittiwake 沉船结构开阔且适合摄影','浅沙地可观察南方黄貂鱼自然巡游'],route:'西岸日船选择最多；根据风向安排北墙与西墙，通常每日两船潜加岸潜。',safety:'不喂食、不抓握黄貂鱼；沉船内部仅限接受过相应训练的潜水员。'},
  {id:'roatan',name:'罗阿坦岛',en:'Roatán · Honduras',lat:16.32,lng:-86.54,depth:'3–35 m',species:'鹰鳐、海龟、鲸鲨',terrain:'堡礁、裂缝、峭壁',level:'新手友好',rating:5,season:'2–9月',visibility:'20–35 m',temp:'26–29°C',desc:'中美洲大堡礁沿岛屿海岸展开，短船程即可到达珊瑚峡谷、峭壁与平静沙地。潜点密集、价格友好，适合考证和高频潜水假期。',facts:['West End 数分钟船程覆盖多种地形','Mary’s Place 以狭窄火山裂缝闻名','邻近 Utila 季节性有机会寻找鲸鲨'],route:'West End 氛围热闹，West Bay 更偏度假；多数潜店按单潜短船往返，安排灵活。',safety:'雨季径流可能降低能见度；穿越裂缝时保持良好浮力，避免触碰两侧珊瑚。'},
  {id:'ningaloo',name:'宁格鲁礁',en:'Ningaloo Reef · Australia',lat:-22.7,lng:113.67,depth:'3–25 m',species:'鲸鲨、蝠鲼、座头鲸',terrain:'岸礁、潟湖、外礁',level:'新手友好',rating:5,season:'3–10月',visibility:'15–30 m',temp:'22–28°C',desc:'西澳大利亚的世界遗产岸礁紧贴荒漠海岸，鲸鲨、蝠鲼和迁徙座头鲸构成季节性巨物日历，许多珊瑚区从沙滩即可抵达。',facts:['3至7月是鲸鲨季的核心时段','冬季与春季可结合座头鲸观察','Exmouth 与 Coral Bay 覆盖不同海域'],route:'以 Exmouth 或 Coral Bay 为基地；鲸鲨活动多为浮潜，水肺潜水则探索外礁与清洁站。',safety:'阳光与脱水风险高，海岸偏远需规划补给；遵守巨物互动距离并选择许可运营商。'},
  {id:'paracel',name:'西沙群岛',en:'Xisha Islands · South China Sea',lat:16.83,lng:112.33,depth:'5–35 m',species:'海龟、礁鲨、苏眉鱼',terrain:'远海环礁、珊瑚墙',level:'进阶',rating:3,season:'3–6月 / 10–11月',visibility:'20–40 m',temp:'25–30°C',desc:'远离大陆的热带环礁拥有大面积珊瑚礁盘、清澈蓝水与陡峭外礁。较少的陆源泥沙让能见度出色，海龟、苏眉鱼和成群珊瑚鱼构成主要景观。',facts:['外礁珊瑚墙由浅水平台直落深蓝','远海环境使大型鱼类出现率相对较高','部分海域保留连续的大面积桌状珊瑚'],route:'通常以获得许可的船宿行程前往，航程长且班期有限；预订前确认最新开放政策。',safety:'区域偏远且天气变化快，医疗撤离困难；必须选择合规运营方并准备潜水保险。'},
  {id:'weizhou',name:'涠洲岛',en:'Weizhou Island · Guangxi, China',lat:21.03,lng:109.11,depth:'3–18 m',species:'海兔、海马、珊瑚鱼',terrain:'火山岩礁、珊瑚斑块',level:'新手友好',rating:4,season:'4–10月',visibility:'3–15 m',temp:'20–30°C',desc:'中国年轻火山岛周围分布着熔岩礁石、沙地和近岸珊瑚群落。潜水条件受季风与降雨影响较大，但交通便利，是体验北部湾水下生态的友好入口。',facts:['火山熔岩地形形成沟槽与生物藏身处','微距可寻找海兔、海马和虾蟹','平静季节适合体验潜水与基础课程'],route:'从北海乘船登岛，潜点多由岛上潜店安排短程快艇抵达；避开强降雨后的低能见度时段。',safety:'只选择资质清晰的潜店；近岸船只较多，升水必须使用水面标识并听从导潜安排。'},
  {id:'green-island',name:'台湾绿岛',en:'Green Island · Taiwan, China',lat:22.66,lng:121.49,depth:'5–35 m',species:'海龟、豆丁海马、隆头鱼',terrain:'火山峭壁、珊瑚礁',level:'全级别',rating:5,season:'4–10月',visibility:'15–30 m',temp:'23–29°C',desc:'黑潮为火山岛带来清澈暖水与丰富生物。岸潜点密集，从平缓珊瑚坡到深水峭壁均可选择，巨大微孔珊瑚与多样微距生物尤其具有代表性。',facts:['石朗拥有体型巨大的大香菇微孔珊瑚','柴口缓坡与平台适合新手岸潜','外侧潜点可见海龟、金枪鱼和大型鱼群'],route:'从台东搭船或短程航班抵达，住岛三至四晚可根据风向灵活选择东西海岸。',safety:'台风与东北季风显著影响船班和浪况；岸潜注意湿滑礁石、浪涌和机车运输装备安全。'},
  {id:'maui',name:'茂宜岛莫洛基尼',en:'Molokini Crater · Hawaii',lat:20.63,lng:-156.5,depth:'5–40 m',species:'蝠鲼、礁鲨、座头鲸',terrain:'火山口、外墙',level:'全级别',rating:4,season:'5–9月',visibility:'25–45 m',temp:'24–27°C',desc:'新月形火山口为内侧浅礁挡住大部分海浪，外侧 Backwall 则垂直落入深蓝。极佳能见度、夏威夷特有鱼种与冬季座头鲸歌声构成鲜明特色。',facts:['火山口内侧平静，适合初学者','Backwall 提供深水峭壁与远洋生物机会','冬季潜水时常可听到座头鲸鸣唱'],route:'清晨从茂宜岛南岸出船，较早班次通常海况更平稳；行程多搭配附近第二潜点。',safety:'外墙可能有流且深度快速增加；遵守夏威夷海洋保护规定，不追逐海龟与海豚。'},
  {id:'kona',name:'科纳蝠鲼夜潜',en:'Kona · Hawaii',lat:19.74,lng:-156.06,depth:'5–18 m',species:'巨型蝠鲼、海豚、海龟',terrain:'火山岩礁、沙地清洁站',level:'新手友好',rating:5,season:'全年',visibility:'15–30 m',temp:'24–27°C',desc:'夜幕降临后，灯光吸引浮游生物聚集，巨型蝠鲼在潜水员头顶翻转进食。近距离但不接触的观察方式，创造出世界上最具辨识度的夜潜体验之一。',facts:['蝠鲼会在固定进食区反复盘旋','白天可探索熔岩管、拱门与海龟礁','黑水潜水能观察从深海垂直迁徙的幼体'],route:'住在夏威夷大岛科纳海岸，选择遵守 Manta Ray Green List 规范的运营商参加傍晚双潜。',safety:'保持在指定位置并让蝠鲼主动接近；禁止触摸动物，夜潜需熟悉备用灯与潜伴程序。'},
  {id:'turks-caicos',name:'特克斯和凯科斯',en:'Turks & Caicos · Caribbean',lat:21.78,lng:-71.75,depth:'5–40 m',species:'鹰鳐、海龟、礁鲨',terrain:'珊瑚墙、沙地',level:'全级别',rating:5,season:'11–5月',visibility:'25–45 m',temp:'25–29°C',desc:'浅色沙洲边缘突然转为深蓝峭壁，形成加勒比最经典的墙潜景观之一。清澈海水、健康海绵与大型海扇适合广角摄影，也为新手提供舒适条件。',facts:['西凯科斯与法属礁拥有壮观垂直外墙','清澈沙地常见南方黄貂鱼与花园鳗','冬春季航行中可能遇见迁徙座头鲸'],route:'普罗维登西亚莱斯适合日船；想覆盖偏远岛礁，可选择一周左右船宿。',safety:'峭壁深度没有视觉参照，需频繁查看深度；日晒强烈，长时间船宿注意补水。'},
  {id:'saba',name:'萨巴岛',en:'Saba · Dutch Caribbean',lat:17.63,lng:-63.24,depth:'5–40 m',species:'礁鲨、海龟、海马',terrain:'海山、熔岩尖塔、峭壁',level:'中级',rating:4,season:'全年',visibility:'20–35 m',temp:'26–29°C',desc:'陡峭火山岛周围几乎没有沙滩，水下熔岩尖塔从深海升起。海山顶端覆盖海绵和珊瑚，四周是鲨鱼、金枪鱼与杰克鱼巡游的开放蓝水。',facts:['Eye of the Needle 是标志性水下熔岩尖塔','海洋公园实施固定系泊，避免锚损珊瑚','近岸峭壁兼有微距与大型鱼类'],route:'从圣马丁搭飞机或渡轮抵达；岛上潜店以小艇运行，每日安排两至三潜。',safety:'入水点深且偶有强流，需快速集合；岛上道路陡峭，运输和天气应预留时间。'},
  {id:'fernando-noronha',name:'费尔南多迪诺罗尼亚',en:'Fernando de Noronha · Brazil',lat:-3.86,lng:-32.42,depth:'5–40 m',species:'旋转海豚、海龟、礁鲨',terrain:'火山岩礁、洞穴、峭壁',level:'全级别',rating:4,season:'8–11月',visibility:'20–50 m',temp:'26–29°C',desc:'巴西大西洋外海的火山群岛拥有全国顶尖能见度。海豚群清晨进入海湾，海龟、礁鲨和大型鱼群环绕熔岩地形，是陆上与水下景观同样出色的保护区。',facts:['清澈季节能见度可超过40米','旋转海豚常在海湾集体活动','Pedras Secas 拥有隧道、拱门和密集鱼群'],route:'从累西腓或纳塔尔飞抵，需支付环境保护费用；潜店日船覆盖内海外海。',safety:'部分潜点仅在特定浪况开放；严格遵守国家公园规则并确认当前游客容量限制。'},
  {id:'zanzibar',name:'桑给巴尔姆内巴环礁',en:'Mnemba Atoll · Tanzania',lat:-5.82,lng:39.39,depth:'5–30 m',species:'海豚、海龟、叶鱼',terrain:'环礁、沙地、缓坡',level:'新手友好',rating:5,season:'10–3月 / 6–9月',visibility:'15–30 m',temp:'25–29°C',desc:'东非海岸外的浅水环礁以白沙、蓝水和多彩珊瑚坡闻名。海豚、海龟和小型礁鱼为轻松潜水增添惊喜，条件适合课程与水下摄影。',facts:['缓坡珊瑚礁适合初学者和长时间观察','沙地可寻找叶鱼、海马与微距生物','航行途中有机会观察宽吻海豚'],route:'从桑给巴尔东北岸出发航程最短；可与岛上香料、石头城行程组合。',safety:'潮汐影响上船地点与水流；选择不追逐、不围堵海豚的负责任运营商。'},
  {id:'andaman',name:'安达曼群岛',en:'Andaman Islands · India',lat:11.68,lng:92.76,depth:'5–35 m',species:'儒艮、蝠鲼、礁鲨',terrain:'火山岩礁、峭壁、珊瑚花园',level:'中级',rating:4,season:'11–4月',visibility:'15–35 m',temp:'27–30°C',desc:'孟加拉湾深处的群岛兼有火山地形、清澈外礁与茂密珊瑚。哈夫洛克岛周边潜点可达性较好，更偏远的海山则吸引蝠鲼、鲨鱼与大型鱼群。',facts:['Barren Island 活火山周边拥有黑色岩壁','Neil Island 浅礁适合新手与微距观察','外海海山有机会遇见蝠鲼和远洋鱼类'],route:'经布莱尔港进入群岛，以 Swaraj Dweep 为主要潜水基地；偏远火山行程需特别许可与好天气。',safety:'部分区域受保护或禁止进入，必须通过持证运营商确认许可；偏远潜点注意燃油、氧气与撤离能力。'},
  {id:'chuuk',name:'楚克沉船群',en:'Chuuk Lagoon · Micronesia',lat:7.45,lng:151.84,depth:'5–60 m',species:'软珊瑚、礁鲨、海龟',terrain:'二战沉船、潟湖',level:'进阶',rating:2,season:'12–4月',visibility:'15–30 m',temp:'27–30°C',desc:'广阔潟湖中沉睡着数十艘二战时期舰船与运输船，甲板、炮台、飞机和货舱逐渐被软珊瑚覆盖，历史遗迹与海洋生态在这里融为一体。',facts:['富士川丸与山鬼山丸是代表性沉船','浅层上层建筑适合休闲潜水观察','深舱与机舱为技术沉船潜水提供复杂路线'],route:'可入住维诺岛潜店或选择船宿；至少安排五个潜水日，逐步适应深度并覆盖不同沉船。',safety:'穿透沉船必须具备专项训练、冗余气源与导线；注意锋利金属、淤泥和未爆物，禁止带走遗物。'},
  {id:'similan',name:'斯米兰群岛',en:'Similan Islands · Thailand',lat:8.65,lng:97.64,depth:'5–35 m',species:'蝠鲼、鲸鲨、豹纹鲨',terrain:'花岗岩巨石、珊瑚坡',level:'中级',rating:4,season:'11–4月',visibility:'20–35 m',temp:'27–30°C',desc:'安达曼海中的花岗岩岛链，水下巨石形成通道、峡谷和开阔泳道。东侧珊瑚坡平缓，西侧巨石与远洋水域更具戏剧性。',facts:['Elephant Head Rock 以巨石迷宫闻名','Richelieu Rock 季节性有机会遇见鲸鲨','西侧潜点常有蝠鲼、金枪鱼和大型鱼群'],route:'从考拉或普吉出发，船宿能覆盖斯米兰、苏林与 Richelieu Rock；国家公园雨季关闭。',safety:'部分巨石区有浪涌和强流；确认国家公园开放日期，不进入没有自然光出口的狭窄空间。'},
  {id:'musandam',name:'穆桑达姆半岛',en:'Musandam · Oman',lat:26.2,lng:56.36,depth:'5–35 m',species:'鲸鲨、鹰鳐、海马',terrain:'峡湾、岩壁、珊瑚礁',level:'全级别',rating:4,season:'10–5月',visibility:'5–25 m',temp:'22–31°C',desc:'陡峭荒漠山脉直接坠入霍尔木兹海峡，形成被称为“阿拉伯峡湾”的海岸。营养丰富的水体带来密集鱼群、软珊瑚和季节性鲸鲨。',facts:['岩壁下分布海扇、软珊瑚与洞穴','夏季浮游生物增多时鲸鲨机会提升','峡湾内外潜点可根据海况灵活切换'],route:'可从阿联酋迪巴参加日船或以阿曼哈萨卜为基地；跨境路线需提前确认签证与口岸要求。',safety:'潮流与能见度变化明显，霍尔木兹海峡船运繁忙；升水必须使用象拔并靠近潜伴。'},
  {id:'tofo',name:'托福海滩',en:'Tofo · Mozambique',lat:-23.85,lng:35.54,depth:'8–35 m',species:'鲸鲨、礁蝠鲼、座头鲸',terrain:'礁台、沙地清洁站',level:'进阶',rating:3,season:'10–3月',visibility:'8–25 m',temp:'24–29°C',desc:'莫桑比克海岸是大型滤食动物的重要活动区。礁蝠鲼在清洁站盘旋，鲸鲨沿近岸觅食，冬季座头鲸迁徙又为蓝水增添巨大的声音与身影。',facts:['Manta Reef 是知名蝠鲼清洁站','海洋巡游途中常寻找鲸鲨并下水观察','冬季可听见座头鲸歌声并偶遇母子鲸'],route:'以托福村为基地，硬底充气艇从沙滩穿浪出海；建议预留天气取消日。',safety:'浪区上下船、负浮力入水和水面漂流要求良好体能；大型动物互动保持距离，不追赶。'},
  {id:'tiger-beach',name:'虎滩',en:'Tiger Beach · Bahamas',lat:26.86,lng:-79.05,depth:'5–15 m',species:'虎鲨、柠檬鲨、大锤头鲨',terrain:'浅沙地、珊瑚块',level:'进阶',rating:2,season:'10–1月',visibility:'20–40 m',temp:'24–29°C',desc:'巴哈马大巴哈马岛外的浅沙地，是观察虎鲨最具代表性的地点之一。明亮自然光和清澈浅水让潜水员能够长时间、低耗气地观察多种鲨鱼。',facts:['虎鲨与柠檬鲨可在同一潜次出现','冬季增加大锤头鲨相遇机会','白沙背景适合鲨鱼行为与广角摄影'],route:'可从西棕榈滩参加船宿，或从大巴哈马岛搭乘专业鲨潜船；选择经验丰富的运营商。',safety:'这是受控诱引潜水，必须严格遵守站位、着装和入出水程序；不可擅自离队或触碰鲨鱼。'},
  {id:'channel-islands',name:'海峡群岛',en:'Channel Islands · California',lat:34.0,lng:-119.75,depth:'5–35 m',species:'海狮、巨型海鲈、海兔',terrain:'海带森林、岩礁、洞穴',level:'中级',rating:4,season:'8–11月',visibility:'8–25 m',temp:'12–19°C',desc:'南加州外海的冷水群岛拥有高耸海带森林、海狮栖息地和岩石礁脉。阳光穿过海带冠层形成水下森林般的空间，是温带潜水的经典画面。',facts:['海狮常主动接近并与潜水员互动','巨型海鲈在夏秋季较常出现','不同岛屿分布沉船、洞穴与海带林'],route:'从文图拉或圣塔芭芭拉参加一日潜水船，也可选择多日船宿探索外侧岛屿。',safety:'冷水、浪涌和海带缠绕要求良好浮力；携带切割工具并具备合适保温装备。'},
  {id:'gods-pocket',name:'上帝口袋',en:"God's Pocket · Canada",lat:50.84,lng:-127.58,depth:'5–40 m',species:'巨型太平洋章鱼、海狮、狼鳗',terrain:'冷水峭壁、海藻林',level:'进阶',rating:2,season:'3–10月',visibility:'8–25 m',temp:'7–12°C',desc:'温哥华岛北端的冷水水道受到潮汐冲刷，岩壁覆盖巨型海葵、海绵与软珊瑚。色彩密度出乎意料，海狮、狼鳗和巨型太平洋章鱼为潜次增添北太平洋性格。',facts:['潮流为峭壁带来高密度无脊椎生物','海狮在特定海湾形成季节性聚集',' Browning Wall 以鲜艳冷水珊瑚闻名'],route:'从 Port Hardy 转乘度假村船只入住偏远小岛，通常采用多日全包潜水形式。',safety:'仅适合熟练干衣潜水员；潮汐窗口严格，水温低且撤离距离长，必须执行保守计划。'},
  {id:'lofoten',name:'罗弗敦群岛',en:'Lofoten · Norway',lat:68.21,lng:14.48,depth:'5–35 m',species:'虎鲸、鳕鱼、帝王蟹',terrain:'峡湾、海带森林、沉船',level:'进阶',rating:2,season:'2–4月 / 10–1月',visibility:'10–30 m',temp:'4–11°C',desc:'北极圈内锋利山峰延伸到寒冷峡湾，水下是茂密海带森林、鳕鱼群与保存良好的沉船。冬季极夜、北极光和虎鲸季让环境格外独特。',facts:['海带森林覆盖岩礁并形成温带生态系统','二战沉船分布在多个避风峡湾','冬季鲱鱼迁徙吸引虎鲸进入北挪威海域'],route:'以斯沃尔韦尔或周边渔村为基地；虎鲸活动通常是专门浮潜行程，不与常规水肺混合。',safety:'需要成熟干衣、冷水和低光经验；天气变化快，注意结冰、风寒和日照时间。'},
  {id:'jeju',name:'济州岛文岛',en:'Munseom · Jeju, Korea',lat:33.23,lng:126.57,depth:'5–30 m',species:'软珊瑚、海兔、豆丁海马',terrain:'火山岩壁、海蚀洞',level:'中级',rating:4,season:'6–11月',visibility:'8–25 m',temp:'14–27°C',desc:'暖流与冷水在济州南岸交汇，使火山岩壁覆盖色彩浓烈的软珊瑚。文岛、虎岛周边兼有峭壁、洞穴与微距生物，是东北亚独特的温带潜水区域。',facts:['大型软珊瑚群落覆盖垂直岩壁','季节变化带来不同鱼群和微距生物','火山岩沟槽为章鱼、海兔提供栖息地'],route:'从西归浦港乘小船前往离岛，也有部分岸潜点；秋季通常兼具较暖水温与较好能见度。',safety:'潮汐流与浪涌随天气变化迅速；冬春水温低，按季节使用厚湿衣或干衣。'},
  {id:'milne-bay',name:'米尔恩湾',en:'Milne Bay · Papua New Guinea',lat:-10.31,lng:150.4,depth:'3–35 m',species:'蝠鲼、躄鱼、海蛞蝓',terrain:'黑沙、海山、珊瑚墙',level:'中级',rating:4,season:'5–11月',visibility:'10–35 m',temp:'26–29°C',desc:'巴布亚新几内亚东端把原始珊瑚礁与经典微距潜水结合在同一片海湾。黑沙坡孕育奇异小生物，外海海山和珊瑚墙则聚集鱼群与蝠鲼。',facts:['Dinah’s Beach 是 muck diving 发展史上的重要潜点','珊瑚海山拥有高密度海扇与鱼群','可在同一天切换微距与广角主题'],route:'从阿洛陶搭乘日船或船宿；船宿能覆盖更偏远的海山、岛礁与不同生态带。',safety:'偏远地区通讯与医疗资源有限；选择具备氧气、卫星联络和完善撤离计划的运营商。'},
  {id:'cenotes',name:'尤卡坦天然井',en:'Yucatán Cenotes · Mexico',lat:20.32,lng:-87.39,depth:'3–30 m',species:'盲鱼、淡水虾、蝙蝠',terrain:'石灰岩洞、钟乳石、光柱',level:'中级',rating:3,season:'全年',visibility:'50–100 m',temp:'24–26°C',desc:'尤卡坦半岛地下河系通过天然井与地表相连。清澈淡水、锐利光柱、钟乳石和淡海水交界的盐跃层，创造出完全不同于开放海域的空间体验。',facts:['Dos Ojos 以宽阔洞室和自然光通道闻名','The Pit 可观察深井光柱与盐跃层','洞口生态包含小型盲鱼、淡水虾与蝙蝠'],route:'以图卢姆或普拉亚德尔卡曼为基地，参加具备当地洞穴资质向导的小组行程。',safety:'休闲潜水仅限洞穴光照区并保持自然光出口；完整洞潜必须接受专门训练并使用冗余装备。'},
  {id:'cenderawasih',name:'极乐鸟湾',en:'Cenderawasih Bay · Indonesia',lat:-2.55,lng:134.62,depth:'3–35 m',species:'鲸鲨、豆丁海马、隆头鹦嘴鱼',terrain:'海湾礁、沉船、珊瑚墙',level:'中级',rating:4,season:'4–11月',visibility:'10–30 m',temp:'28–30°C',desc:'西巴布亚巨大的半封闭海湾以鲸鲨在传统渔业平台附近长期活动闻名，同时拥有偏远珊瑚礁、二战遗迹和极高的特有物种比例。',facts:['鲸鲨会在 bagan 渔台附近取食小鱼','珊瑚礁中可寻找多种特有鱼类与豆丁海马','Manokwari 周边保存数处二战沉船'],route:'通常从纳比雷进入，采用小型船宿或偏远度假村行程；交通转接较多，应预留缓冲日。',safety:'鲸鲨互动遵守距离与人数限制；海湾偏远，确认船只氧气、通讯和撤离方案。'},
  {id:'wakatobi',name:'瓦卡托比',en:'Wakatobi · Indonesia',lat:-5.48,lng:123.76,depth:'3–40 m',species:'海龟、鹰鳐、豆丁海马',terrain:'珊瑚墙、海草床、礁坡',level:'全级别',rating:5,season:'3–12月',visibility:'20–40 m',temp:'26–29°C',desc:'苏拉威西东南部的偏远群岛拥有高覆盖率珊瑚墙与成熟海洋保护机制。浅礁色彩丰富，深水墙面布满海扇，宏观和微距题材可以在一潜中连续切换。',facts:['House Reef 可从码头直接进入并长时间岸潜','海草床为海龟、海马和幼鱼提供栖息地','珊瑚墙上常见大型海扇与成群蝴蝶鱼'],route:'可入住专门潜水度假村或从当地港口参加船宿，适合安排一周以上慢节奏行程。',safety:'保护区强调低影响潜水；保持精确浮力，不触碰海扇或站立在浅礁。'},
  {id:'bunaken',name:'布纳肯',en:'Bunaken · Indonesia',lat:1.62,lng:124.76,depth:'5–40 m',species:'海龟、礁鲨、海蛇',terrain:'垂直珊瑚墙',level:'全级别',rating:5,season:'3–10月',visibility:'20–35 m',temp:'27–30°C',desc:'布纳肯岛周围的礁盘在几米水深处突然切成垂直墙面。密集海龟沿墙休息和觅食，成群珊瑚鱼、海蛇与偶尔经过的鲨鱼构成经典漂流墙潜。',facts:['Lekuan 系列潜点以高密度绿海龟闻名','墙面裂缝聚集海鳗、海蛇和小型甲壳类','潮流带来杰克鱼与金枪鱼等远洋访客'],route:'从万鸦老乘船或直接住在布纳肯岛；日程通常依潮汐安排两至三潜。',safety:'墙外深度没有参照且可能出现强流；持续检查深度和气量，避免追逐海龟下潜。'},
  {id:'anilao',name:'阿尼洛',en:'Anilao · Philippines',lat:13.75,lng:120.92,depth:'3–30 m',species:'海蛞蝓、拟态章鱼、躄鱼',terrain:'黑沙、珊瑚坡、海山',level:'全级别',rating:5,season:'10–5月',visibility:'8–25 m',temp:'25–29°C',desc:'马尼拉以南的微距摄影重镇拥有黑沙、碎石、海草和珊瑚坡等多种小环境。海蛞蝓物种尤其丰富，章鱼、躄鱼和甲壳类夜间活动旺盛。',facts:['Secret Bay 是夜潜与黑沙微距热点','海蛞蝓种类多，适合物种记录摄影','Sombrero Island 可切换到广角珊瑚景观'],route:'从马尼拉陆路约三小时，住在潜水度假村并根据摄影主题与向导制定每日路线。',safety:'摄影时避免长时间占据单一生物；控制呼吸与蛙踢，防止扬沙或压伤微小个体。'},
  {id:'dauin',name:'道因',en:'Dauin · Philippines',lat:9.19,lng:123.27,depth:'3–25 m',species:'蓝环章鱼、海马、鬼龙',terrain:'火山黑沙、海草床',level:'全级别',rating:5,season:'全年',visibility:'8–20 m',temp:'26–30°C',desc:'内格罗斯岛东南岸的火山黑沙坡是微距生物宝库。人工礁、海草和零散珊瑚为稀有头足类、海马、鬼龙与幼年鱼类提供庇护。',facts:['夜潜常见椰子章鱼、蓝环章鱼与乌贼','海草中可寻找海马、鬼龙和微小甲壳类','可搭配阿波岛进行一日广角珊瑚潜水'],route:'住在道因海岸即可步行岸潜；潜店通常提供不限次数岸潜和阿波岛日船。',safety:'部分有毒生物体型很小且伪装出色；不翻动、抓握或围堵动物，夜潜使用柔和灯光。'},
  {id:'gili',name:'吉利群岛',en:'Gili Islands · Indonesia',lat:-8.35,lng:116.06,depth:'5–30 m',species:'绿海龟、玳瑁、白鳍礁鲨',terrain:'珊瑚坡、沙地、沉船',level:'新手友好',rating:5,season:'5–10月',visibility:'15–30 m',temp:'27–30°C',desc:'龙目岛西北侧三座小岛以高频海龟相遇、温暖海水和成熟课程体系著称。平缓沙坡适合学习，礁角与沉船又为进阶潜水员提供更多变化。',facts:['Turtle Heaven 周边常有多只绿海龟休息','沙地可观察花园鳗、魟鱼与微距生物','Shark Point 有机会遇见白鳍礁鲨'],route:'可从巴厘岛乘快船或从龙目岛转船；三岛潜店共享大量短船程潜点。',safety:'热门潜点船只和潜水员较多，保持队形并规范放象拔；不要触摸或阻挡海龟上浮。'},
  {id:'koh-tao',name:'涛岛',en:'Koh Tao · Thailand',lat:10.1,lng:99.84,depth:'3–30 m',species:'鲸鲨、海龟、蓝点魟',terrain:'花岗岩礁、沙地',level:'新手友好',rating:5,season:'3–9月',visibility:'8–25 m',temp:'27–30°C',desc:'泰国湾著名潜水教学岛，平静浅水、较短船程和大量潜店使其成为考证热门地。离岸海山偶有鲸鲨出现，也能观察海龟和热带礁鱼。',facts:['Chumphon Pinnacle 是鲸鲨与大型鱼群热点','Japanese Gardens 条件平静，适合课程训练','Sail Rock 的垂直烟囱地形极具辨识度'],route:'从苏梅岛或春蓬乘船抵达；选择小班教学并查看教练与潜店资质。',safety:'教学旺季水下拥挤，注意与其他队伍保持距离；鲸鲨出现时避免追逐和阻挡行进路线。'},
  {id:'elphinstone',name:'埃尔芬斯通礁',en:'Elphinstone Reef · Egypt',lat:25.31,lng:34.86,depth:'10–40 m',species:'长尾鲨、远洋白鳍鲨、锤头鲨',terrain:'远海海山、峭壁',level:'专家',rating:2,season:'9–11月',visibility:'25–40 m',temp:'23–30°C',desc:'红海南部一条狭长远海礁体，南北高原伸向开放海域。鲨鱼沿深水边缘巡游，峭壁覆盖软珊瑚，是大场面与高难度并存的代表潜点。',facts:['秋季较常观察远洋白鳍鲨靠近礁体','北侧深水有机会遇见长尾鲨与锤头鲨','东西墙适合顺流观察软珊瑚和远洋鱼类'],route:'可从 Marsa Alam 日船抵达，也常被纳入红海南线或 BDE 船宿。',safety:'强流与蓝水上升要求丰富经验；禁止追逐鲨鱼，听从导潜关于入水方向和集合点的简报。'},
  {id:'sanganeb',name:'桑加尼布礁',en:'Sanganeb Reef · Sudan',lat:19.73,lng:37.44,depth:'5–40 m',species:'锤头鲨、灰礁鲨、隆头鱼',terrain:'远海环礁、灯塔峭壁',level:'进阶',rating:3,season:'2–5月 / 10–11月',visibility:'25–45 m',temp:'26–30°C',desc:'苏丹红海中央的孤立环礁以灯塔、清澈深蓝和保存良好的珊瑚墙闻名。游客密度低，礁角鱼群与鲨鱼活动呈现更原始的远海气质。',facts:['北侧高原有机会观察锤头鲨群','南侧平台聚集灰礁鲨、杰克鱼与梭鱼','珊瑚墙上分布海扇、黑珊瑚与软珊瑚'],route:'通常由苏丹港出发参加船宿，并与 Sha’ab Rumi 等潜点组成一周路线。',safety:'当地旅行条件和开放状态可能变化，预订前核实最新信息；远海潜次携带定位设备。'},
  {id:'aldabra',name:'阿尔达布拉环礁',en:'Aldabra Atoll · Seychelles',lat:-9.41,lng:46.34,depth:'5–35 m',species:'绿海龟、儒艮、礁鲨',terrain:'巨大潟湖、水道、外礁',level:'专家',rating:2,season:'3–5月 / 10–11月',visibility:'15–35 m',temp:'26–29°C',desc:'世界最大的抬升珊瑚环礁之一，受严格保护且极难抵达。潮汐通过狭窄水道进出巨大潟湖，维持海龟、鲨鱼、魟鱼和罕见儒艮种群。',facts:['拥有全球重要的绿海龟繁殖种群','潟湖水道中可见鲨鱼与魟鱼顺流移动','偏远环境保留完整的珊瑚礁食物网'],route:'仅少量获许可探险船在特定季节到访，行程通常超过十天且价格较高。',safety:'严格遵守保护区许可和生物安全规则；潮流强、撤离距离极远，只适合经验丰富者。'},
  {id:'reunion',name:'留尼汪岛',en:'Réunion · Indian Ocean',lat:-21.13,lng:55.28,depth:'5–40 m',species:'座头鲸、海龟、鹰鳐',terrain:'火山岩礁、深水峭壁',level:'中级',rating:4,season:'5–11月',visibility:'15–35 m',temp:'23–29°C',desc:'活火山岛的陆地坡度延伸入海，形成熔岩流、峡谷和快速下降的峭壁。南半球冬季座头鲸迁徙经过近岸，为常规珊瑚与海龟潜水增添季节亮点。',facts:['冬季水下可能听到座头鲸歌声','熔岩岩脊上分布海扇和热带鱼群','海龟常在西岸保护礁区觅食休息'],route:'以 Saint-Gilles-les-Bains 为主要基地，潜点多在西岸背风侧。',safety:'岛屿外海浪涌和流况可快速变化；鲸类保持法定距离，不主动靠近母子鲸。'},
  {id:'sardine-run',name:'南非沙丁鱼迁徙',en:'Sardine Run · South Africa',lat:-31.8,lng:29.5,depth:'0–25 m',species:'沙丁鱼、海豚、鲨鱼、鲸',terrain:'开放蓝水、饵球',level:'专家',rating:1,season:'6–7月',visibility:'5–20 m',temp:'18–23°C',desc:'亿万沙丁鱼沿南非东海岸向北迁徙，海豚把鱼群驱赶成饵球，鲨鱼、塘鹅与鲸类从水下和空中加入捕食。这不是固定潜点，而是一场需要搜索和等待的动态生态事件。',facts:['普通海豚群通过协作把沙丁鱼压成饵球','黑鳍鲨、铜鲨和灰鲭鲨可能同时出现','塘鹅高速入水与鲸类捕食构成立体场面'],route:'从东开普或夸祖鲁-纳塔尔沿岸参加约一周专业追踪行程，每日乘充气艇寻找鸟群和海豚。',safety:'开放海域、低温、浪涌与大型动物密集，只适合体能良好者；多数观察采用浮潜或快速负浮力下潜。'},
  {id:'false-bay',name:'开普敦福尔斯湾',en:'False Bay · South Africa',lat:-34.2,lng:18.65,depth:'5–30 m',species:'七鳃鲨、海狗、海兔',terrain:'巨藻森林、花岗岩礁',level:'中级',rating:4,season:'10–5月',visibility:'5–20 m',temp:'10–18°C',desc:'开普半岛两侧的冷水巨藻森林覆盖花岗岩礁，七鳃鲨、海狗和色彩鲜艳的温带无脊椎动物生活其中，景观与热带珊瑚礁截然不同。',facts:['巨藻冠层形成光影不断变化的水下森林','Millers Point 一带可寻找宽鼻七鳃鲨','海狗会在浅水主动接近并模仿潜水员动作'],route:'根据风向在福尔斯湾与大西洋侧切换岸潜或船潜；当地向导最了解短暂能见度窗口。',safety:'冷水、浪涌与岸潜入水点需要合适装备；野生动物出现无保证，禁止诱引或触摸。'},
  {id:'scapa-flow',name:'斯卡帕湾',en:'Scapa Flow · Scotland',lat:58.88,lng:-3.08,depth:'12–45 m',species:'海豹、鳕鱼、海葵',terrain:'一战沉船、天然港湾',level:'进阶',rating:2,season:'5–10月',visibility:'5–20 m',temp:'8–14°C',desc:'奥克尼群岛天然港湾内沉睡着德国公海舰队的一战残骸。巨大战列舰与巡洋舰侧卧海床，钢铁结构覆盖海葵、海绵与冷水生物。',facts:['SMS Markgraf 等战列舰体量极具震撼力','巡洋舰上层结构适合休闲深度观察','金属表面已成为鳕鱼、海绵和海葵栖息地'],route:'从 Stromness 参加六天左右的专业沉船船宿或日船，通常每日两潜。',safety:'低温、低光和大体量沉船易造成方向迷失；使用干衣、双灯，并按训练限制穿透范围。'},
  {id:'vis',name:'维斯岛',en:'Vis Island · Croatia',lat:43.04,lng:16.16,depth:'5–50 m',species:'石斑鱼、海鳗、章鱼',terrain:'洞穴、峭壁、飞机沉骸',level:'中级',rating:3,season:'5–10月',visibility:'20–40 m',temp:'15–26°C',desc:'亚得里亚海的偏远石灰岩岛屿周围散布蓝洞、峭壁、古代遗迹与近现代沉船。高能见度让飞机与船体轮廓在深水中清晰可辨。',facts:['B-17 飞机沉骸是技术潜水代表目标','海蚀洞与蓝洞拥有强烈自然光景观','岩缝常见章鱼、海鳗和地中海石斑鱼'],route:'从斯普利特乘渡轮到维斯岛，以 Komiža 或 Vis Town 为基地安排岸船结合潜水。',safety:'多处沉骸超过休闲深度；不要因优秀能见度低估深度和氮醉风险。'},
  {id:'baikal',name:'贝加尔湖',en:'Lake Baikal · Russia',lat:53.15,lng:107.38,depth:'5–40 m',species:'贝加尔海豹、端足类、海绵',terrain:'淡水峭壁、冰层、海绵林',level:'专家',rating:1,season:'2–3月 / 7–9月',visibility:'20–40 m',temp:'0–12°C',desc:'世界最深湖泊拥有高度特有的淡水生态。透明冰层、陡峭湖底与绿色海绵群落创造出近乎外星的景观，幸运时还能观察唯一的淡水海豹之一。',facts:['贝加尔海豹是湖区最具代表性的特有哺乳动物','特有端足类与海绵构成重要底栖群落','冬季冰潜可观察裂纹、气泡和蓝色冰层'],route:'以利斯特维扬卡或奥尔洪岛为基地；冰潜必须参加配备水面支援和安全绳的专业团队。',safety:'极冷淡水、海拔与冰层环境风险叠加；必须具备干衣和冰潜训练，使用系绳与冗余调节器。'},
  {id:'antarctic',name:'南极半岛',en:'Antarctic Peninsula',lat:-64.8,lng:-62.8,depth:'3–20 m',species:'豹海豹、企鹅、海星',terrain:'冰山、岩礁、冰壁',level:'专家',rating:1,season:'11–3月',visibility:'5–30 m',temp:'-1–2°C',desc:'冰山水下部分、蓝色冰壁和巨型底栖无脊椎动物组成地球最极端的休闲潜水环境。企鹅可能高速掠过水面，海豹则在冰缘巡游。',facts:['冷水巨型化使海星、海绵等底栖生物体型突出','冰山水下纹理会随融化不断变化','可能观察企鹅入水与威德尔海豹活动'],route:'仅通过具备潜水许可与专业团队的南极探险船参加，潜点完全由冰况和天气决定。',safety:'要求丰富干衣与近冰点水温经验；双独立调节器防冻结，严格执行系潜伴、短潜时与撤离程序。'},
  {id:'fakarava',name:'法卡拉瓦环礁',en:'Fakarava · French Polynesia',lat:-16.05,lng:-145.62,depth:'5–35 m',species:'灰礁鲨、锤头鲨、石斑鱼',terrain:'环礁水道、珊瑚墙',level:'进阶',rating:3,season:'5–10月',visibility:'25–45 m',temp:'26–29°C',desc:'巨大的联合国生物圈保护区只有少数水道连接潟湖与外海。潮汐把清澈海水和猎物带入狭窄通道，形成著名的灰礁鲨墙与季节性石斑鱼繁殖聚集。',facts:['南水道长期聚集数百尾灰礁鲨','初夏石斑鱼产卵吸引更多捕食者','潟湖内珊瑚花园适合轻松浅潜'],route:'搭乘国内航班抵达北水道村落；南水道需住简朴旅宿或参加覆盖两端的船宿。',safety:'水道潜水严格依赖进流窗口；出流可能把潜水员带向外海，不可脱离导潜路线。'},
  {id:'rangiroa',name:'朗伊罗阿环礁',en:'Rangiroa · French Polynesia',lat:-14.95,lng:-147.65,depth:'5–35 m',species:'宽吻海豚、灰礁鲨、锤头鲨',terrain:'深水水道、潟湖',level:'进阶',rating:3,season:'9–3月',visibility:'25–45 m',temp:'26–29°C',desc:'世界大型环礁之一，Tiputa 水道以野生宽吻海豚主动接近潜水员而闻名。潮流同时吸引鲨鱼、鹰鳐、金枪鱼和密集鱼群进出潟湖。',facts:['宽吻海豚有时会主动停留并寻求人类互动','冬季至春季较有机会观察锤头鲨','水道口常聚集灰礁鲨、杰克鱼和梭鱼'],route:'住在 Tiputa 或 Avatoru 水道附近，潜店会依据每日潮汐安排进流与外礁潜次。',safety:'尊重海豚自主选择，不主动追逐或触摸；强流时保持队形并熟练放象拔。'},
  {id:'bohol',name:'薄荷岛',en:'Bohol · Philippines',lat:9.59,lng:123.76,depth:'3–40 m',species:'海龟、杰克鱼、沙丁鱼、鲸鲨',terrain:'珊瑚墙、海草床、沙地',level:'全级别',rating:5,season:'11–5月',visibility:'15–30 m',temp:'27–30°C',desc:'薄荷岛及邦劳周边兼有轻松岸潜、峭壁和大型鱼群。巴里卡萨岛的垂直珊瑚墙、杰克鱼群与高频海龟相遇，是菲律宾最成熟的综合型潜水体验之一。',facts:['巴里卡萨岛常见密集杰克鱼群沿墙旋转','浅水海草床与珊瑚坡有大量绿海龟','Napaling 外海可观察近岸沙丁鱼群'],route:'以邦劳岛为基地，安排巴里卡萨一日船与本地岸潜；巴里卡萨名额应提前预约。',safety:'热门潜点船只与潜水员较多；不要阻挡海龟上浮，鲸鲨活动应选择不投喂、不围堵的运营商。'},
  {id:'xiaoliuqiu',name:'小琉球',en:'Xiaoliuqiu · Taiwan, China',lat:22.34,lng:120.37,depth:'3–25 m',species:'绿海龟、海兔、海蛇',terrain:'珊瑚礁、海龟海草区、沉船',level:'新手友好',rating:5,season:'全年',visibility:'8–25 m',temp:'22–29°C',desc:'台湾西南侧的珊瑚礁岛因全年相对温暖、岸潜便利和极高绿海龟相遇率而闻名。浅礁、海草和礁洞构成适合新手与水下摄影的紧凑生态。',facts:['多个岸潜点可稳定观察绿海龟觅食与休息','花瓶岩周边浅礁适合浮潜和体验潜水','沉船与礁洞为进阶者提供不同地形'],route:'从东港乘短程渡轮抵达，岛上潜店以岸潜为主；清晨和非周末时段水下较安静。',safety:'与海龟保持距离，不触摸、不骑乘、不阻挡呼吸路线；岸潜注意潮位、礁石和船道。'},
  {id:'tioman',name:'刁曼岛',en:'Tioman Island · Malaysia',lat:2.79,lng:104.17,depth:'3–30 m',species:'海龟、黑鳍礁鲨、隆头鹦嘴鱼',terrain:'花岗岩礁、珊瑚花园、沉船',level:'新手友好',rating:5,season:'3–10月',visibility:'10–25 m',temp:'27–30°C',desc:'马来半岛东岸的热带岛屿拥有平静海湾、花岗岩巨石和多样浅礁，是课程与轻松潜水的热门选择。外侧小岛则有更好的能见度和大型鱼群。',facts:['Renggis Island 常见海龟、礁鲨和成群礁鱼','Tiger Reef 水流较强，软珊瑚与鱼群密度高','Soyak 与 Labas 的巨石形成泳道和洞口'],route:'从丰盛港或 Tanjung Gemok 乘船，住在 Tekek、Air Batang 或 Salang 均可参加日潜。',safety:'东北季风期间多数服务停运；外侧礁流况变化大，应按证书和经验选择潜点。'},
  {id:'malapascua',name:'妈妈拍丝瓜岛',en:'Malapascua · Philippines',lat:11.33,lng:124.12,depth:'5–30 m',species:'长尾鲨、鬼龙、海马',terrain:'水下高原、珊瑚坡、沉船',level:'进阶',rating:3,season:'全年',visibility:'10–25 m',temp:'26–30°C',desc:'宿务北端的小岛以长尾鲨清洁站闻名。清晨的 Monad 与 Kimud 水下高原提供罕见的稳定观察机会，岛周围也有丰富微距和沉船潜点。',facts:['长尾鲨清晨从深水上升到高原清洁站','Kimud Shoal 也有机会遇见锤头鲨群','夜潜可寻找海马、鬼龙、海兔和甲壳类'],route:'从宿务陆路到 Maya 港再乘小船登岛；建议住四晚以上，为海况和多次长尾鲨潜水留余地。',safety:'清洁站保持低姿态与距离，不越过观察线追鲨；清晨出船较早，注意休息和连续潜水氮负荷。'},
  {id:'coron',name:'科隆湾沉船群',en:'Coron · Philippines',lat:11.98,lng:120.08,depth:'5–40 m',species:'蝎子鱼、海兔、梭鱼',terrain:'二战沉船、湖泊温跃层',level:'进阶',rating:3,season:'10–5月',visibility:'5–20 m',temp:'27–31°C',desc:'巴拉望北部海湾保存着多艘二战时期日本沉船，从浅层甲板到复杂机舱覆盖不同训练等级。附近 Barracuda Lake 的淡咸水与剧烈温跃层则带来近似外星的地质体验。',facts:['Olympia Maru、Akitsushima 等沉船各具结构特色','船体已被珊瑚、海绵和密集鱼群覆盖','Barracuda Lake 水温分层可超过35°C'],route:'以科隆镇为基地，日船通常安排两艘沉船加一处礁区或湖泊；选择专长沉船的潜店。',safety:'未经训练不可深入船舱；沉船内部有淤泥、锋利金属和迷向风险，湖泊高温层需留意热应激。'},
  {id:'nusa-penida',name:'努沙佩尼达',en:'Nusa Penida · Indonesia',lat:-8.73,lng:115.53,depth:'5–40 m',species:'翻车鱼、蝠鲼、海龟',terrain:'清洁站、珊瑚坡、强流水道',level:'进阶',rating:3,season:'7–10月',visibility:'15–35 m',temp:'18–29°C',desc:'巴厘岛东南的深水水道以蝠鲼清洁站和季节性翻车鱼闻名。北岸珊瑚坡适合长距离漂流，南侧冷水上升流则带来大型远洋生物。',facts:['Manta Point 可全年观察礁蝠鲼清洁行为','Crystal Bay 冷水季有机会遇见翻车鱼','北岸缓坡覆盖连续珊瑚并适合漂流潜水'],route:'可从巴厘岛 Sanur 日船往返，也可住在佩尼达岛；最佳潜点和入水时间依潮汐决定。',safety:'温度骤降、下降流和快速水道流并存；不可追逐翻车鱼下深，准备合适防寒衣。'},
  {id:'tulamben',name:'图蓝本',en:'Tulamben · Bali, Indonesia',lat:-8.28,lng:115.59,depth:'3–35 m',species:'隆头鹦嘴鱼、海马、海蛞蝓',terrain:'火山黑沙、自由号沉船、峭壁',level:'新手友好',rating:5,season:'4–11月',visibility:'10–25 m',temp:'27–30°C',desc:'阿贡火山脚下的黑色卵石海岸拥有巴厘岛最著名的自由号沉船。船体从浅水开始，晨间隆头鹦嘴鱼、成群杰克鱼和丰富微距生物让这里适合反复探索。',facts:['USAT Liberty 船体覆盖软珊瑚与海扇','黎明常见隆头鹦嘴鱼从沉船附近经过','黑沙坡可寻找海马、躄鱼与多种海蛞蝓'],route:'住在图蓝本可避开日间人潮并安排黎明、夜间岸潜；装备通常由搬运员送至入水点。',safety:'卵石岸边浪涌会增加进出水难度；沉船内部仅限受训者，避免触碰脆弱结构。'},
  {id:'menjangan',name:'门姜岸岛',en:'Menjangan · Bali, Indonesia',lat:-8.1,lng:114.5,depth:'5–40 m',species:'海龟、鹰鳐、豆丁海马',terrain:'珊瑚墙、沙坡、洞穴',level:'全级别',rating:5,season:'4–11月',visibility:'20–40 m',temp:'27–30°C',desc:'西巴厘国家公园内的离岸小岛以平静清澈水域和色彩丰富的珊瑚墙闻名。海扇、软珊瑚和深蓝背景适合广角，微小海马又为慢速观察提供惊喜。',facts:['Pos II 墙面布满海扇、海绵与软珊瑚','平静海况和较弱水流适合初学者','沙坡与海扇可寻找花园鳗和豆丁海马'],route:'从 Pemuteran 或国家公园码头乘船前往；适合与当地人工礁项目组合两至三天。',safety:'国家公园内遵守分区和费用规定；墙潜持续查看深度，不为拍摄海马触碰宿主海扇。'},
  {id:'derawan',name:'德拉旺群岛',en:'Derawan Islands · Indonesia',lat:2.28,lng:118.24,depth:'3–40 m',species:'蝠鲼、鲸鲨、海龟、水母',terrain:'环礁、水道、海湖',level:'中级',rating:4,season:'3–10月',visibility:'10–30 m',temp:'27–30°C',desc:'东加里曼丹外海群岛把蝠鲼水道、海龟繁殖地、鲸鲨渔台和无刺水母湖集中在同一片区域。不同岛屿各有鲜明生态主题。',facts:['Sangalaki 是重要蝠鲼清洁与觅食区域','Kakaban 海湖生活多种无刺水母','Maratua 水道可见鲨鱼、梭鱼与远洋鱼群'],route:'经 Berau 或 Tarakan 转陆路与快艇进入；船宿或住在 Maratua 更利于覆盖偏远潜点。',safety:'岛际航程长且水道流强；水母湖禁用防晒化学品和脚蹼，鲸鲨互动选择负责任运营商。'},
  {id:'mabul',name:'马布岛',en:'Mabul · Malaysia',lat:4.25,lng:118.63,depth:'3–25 m',species:'躄鱼、海马、蓝环章鱼',terrain:'沙泥坡、人工礁、海草床',level:'全级别',rating:5,season:'4–12月',visibility:'5–20 m',temp:'27–30°C',desc:'诗巴丹邻近的浅水岛屿是世界级微距目的地。码头、人工礁和沙泥坡为躄鱼、海马、章鱼与幼年鱼类提供大量藏身空间。',facts:['Seaventure 平台下聚集鱼群和大型石斑鱼','人工礁可寻找躄鱼、鳄鱼鱼与海马','夜潜常见蓝环章鱼、乌贼和甲壳类'],route:'从仙本那乘快艇，入住岛上或卡帕莱度假村；可作为等待诗巴丹许可期间的核心潜水内容。',safety:'控制蛙踢避免扬沙；有毒小型生物只观察不触碰，码头潜水留意船只和水面结构。'},
  {id:'perhentian',name:'停泊岛',en:'Perhentian Islands · Malaysia',lat:5.91,lng:102.74,depth:'3–25 m',species:'海龟、黑鳍礁鲨、蓝点魟',terrain:'浅礁、花岗岩、沉船',level:'新手友好',rating:5,season:'3–10月',visibility:'10–25 m',temp:'28–30°C',desc:'马来半岛东北岸的两座小岛以平静海湾、短船程和亲民课程体系著称。海龟、幼年黑鳍礁鲨和热带鱼群在浅水即可观察。',facts:['Turtle Bay 海草床常有绿海龟觅食','Shark Point 浅礁可观察幼年黑鳍礁鲨','Sugar Wreck 是覆盖软珊瑚的浅水沉船'],route:'从瓜拉勿述乘快艇登岛；岛上潜店密集，适合三至五天课程或休闲潜水。',safety:'东北季风期间岛屿基本关闭；热门浅礁游客较多，注意水面船只并使用标识。'},
  {id:'redang',name:'热浪岛',en:'Redang Island · Malaysia',lat:5.78,lng:103.01,depth:'3–30 m',species:'海龟、礁鲨、隆头鹦嘴鱼',terrain:'珊瑚花园、海山、沙地',level:'新手友好',rating:5,season:'3–10月',visibility:'15–30 m',temp:'28–30°C',desc:'丁加奴海洋公园内的热浪岛拥有马来西亚半岛东岸较成熟的珊瑚景观。浅水鹿角珊瑚、清澈沙地和外侧海山适合从初学逐步进阶。',facts:['浅湾珊瑚花园聚集大量幼鱼和海龟','Tanjung Tokong 外侧海山可见大型鱼群','夜潜可寻找海兔、蟹类和捕食中的海鳗'],route:'从墨浪码头乘船；度假村多提供住宿与潜水套餐，可搭配附近浪中岛。',safety:'遵守海洋公园禁采集规定；季风前后海况不稳定，确认度假村实际开放日期。'},
  {id:'puerto-galera',name:'海豚湾',en:'Puerto Galera · Philippines',lat:13.52,lng:120.98,depth:'3–40 m',species:'海蛞蝓、礁鲨、杰克鱼',terrain:'水道、珊瑚坡、沉船',level:'全级别',rating:4,season:'11–5月',visibility:'10–30 m',temp:'26–30°C',desc:'民都洛岛北岸处于佛得岛水道生物多样性核心。平静海湾、强流水道、沉船与世界级微距点距离很近，可在短船程内切换完全不同的潜水风格。',facts:['Canyons 强流潜水聚集杰克鱼和梭鱼','Sabang Wrecks 适合微距与夜潜观察','Verde Island Drop Off 拥有极高鱼类密度'],route:'从八打雁乘船抵达 Sabang 或 Puerto Galera；可依经验选择海湾本地潜点或佛得岛远征。',safety:'Canyons 与佛得岛流况复杂，只适合有漂流经验者；繁忙船道升水必须放象拔。'},
  {id:'apo-island',name:'阿波岛',en:'Apo Island · Philippines',lat:9.08,lng:123.27,depth:'3–30 m',species:'海龟、海蛇、杰克鱼',terrain:'海洋保护区、珊瑚坡、岩壁',level:'全级别',rating:5,season:'10–5月',visibility:'15–30 m',temp:'27–30°C',desc:'内格罗斯岛外的小型火山岛是菲律宾社区海洋保护的经典案例。健康硬珊瑚、丰富海龟与鱼群证明长期禁捕和社区管理的生态价值。',facts:['Chapel 与 Coconut Point 展现不同流况和珊瑚地形','浅水区高频观察绿海龟和海蛇','珊瑚覆盖率与礁鱼密度具有保护区代表性'],route:'从道因或 Zamboanguita 参加日船，也可住在岛上体验更安静的清晨潜水。',safety:'Coconut Point 流速可快，需按经验选择；浅水珊瑚非常脆弱，保持良好浮力。'},
  {id:'izu',name:'伊豆半岛',en:'Izu Peninsula · Japan',lat:34.88,lng:138.78,depth:'3–35 m',species:'锤头鲨、海兔、海马',terrain:'火山岩礁、海湾、沉船',level:'全级别',rating:4,season:'7–11月',visibility:'5–25 m',temp:'14–27°C',desc:'东京近郊最重要的潜水区域之一，东岸与西岸拥有大量全年运营的岸潜点。黑潮暖水带来热带访客，温带海藻与季节性鱼群则构成明显四季变化。',facts:['神子元岛夏秋季有机会观察锤头鲨群','大濑崎平静海湾适合训练与微距观察','热海沉船与洞穴为进阶者提供地形路线'],route:'从东京乘铁路或自驾抵达各海湾；依据当天风向在东西海岸切换是当地常见做法。',safety:'神子元岛为强流蓝水潜水，门槛较高；冬季水温低，需干衣或厚湿衣经验。'},
  {id:'mauritius',name:'毛里求斯',en:'Mauritius · Indian Ocean',lat:-20.28,lng:57.37,depth:'5–40 m',species:'飞旋海豚、鹰鳐、礁鲨、海龟',terrain:'火山礁、沉船、峭壁、礁口',level:'全级别',rating:4,season:'10–5月',visibility:'15–35 m',temp:'23–29°C',desc:'毛里求斯的堡礁围出平静潟湖，礁口之外则迅速过渡为火山峭壁、洞穴与沉船。北部适合沉船和礁坡潜水，西部常见海豚，东南部更具野性水流与远洋氛围。',facts:['北部多艘人工沉船已覆盖软珊瑚并聚集鱼群','Cathedral 的拱顶与气泡光线形成独特洞穴景观','礁口附近可见鹰鳐、金枪鱼、海龟与礁鲨'],route:'Grand Baie 潜店最集中；也可住在 Flic-en-Flac 探索西岸洞穴和峭壁，根据季风选择背风海域。',safety:'礁口流速与浪涌随潮汐变化；选择不追逐、不围堵海豚的运营商，洞穴穿越需符合训练等级。'},
  {id:'cocos-keeling',name:'科科斯群岛',en:'Cocos Keeling · Australia',lat:-12.16,lng:96.87,depth:'5–35 m',species:'锤头鲨、蝠鲼、海豚、海龟',terrain:'环礁水道、珊瑚墙、沉船',level:'中级',rating:4,season:'4–11月',visibility:'20–40 m',temp:'26–29°C',desc:'印度洋中央的澳大利亚外岛由低矮珊瑚环礁组成，清澈水道、健康外礁和低游客密度共同塑造安静而原始的潜水环境。',facts:['孤立礁体有机会吸引锤头鲨与蝠鲼','德国巡洋舰 Emden 遗迹具有历史意义','水道中常见海龟、鹰鳐和宽吻海豚'],route:'经珀斯搭乘有限航班抵达，建议停留一周以上，以应对天气和航班变化。',safety:'岛屿偏远、补给和医疗有限；外礁流况变化快，提前确认运营商氧气与撤离能力。'},
  {id:'christmas-island',name:'圣诞岛',en:'Christmas Island · Australia',lat:-10.49,lng:105.63,depth:'5–40 m',species:'鲸鲨、礁鲨、隆头鹦嘴鱼',terrain:'垂直海墙、洞穴、深蓝外海',level:'中级',rating:4,season:'11–4月',visibility:'25–45 m',temp:'27–30°C',desc:'一座从深海陡然升起的石灰岩岛，离岸很近便进入垂直海墙和开放蓝水。红蟹迁徙后的鲸鲨季是最大亮点，近岸珊瑚和巨型鱼类同样出色。',facts:['红蟹繁殖季后鲸鲨常沿岛岸觅食','海墙旁可见隆头鹦嘴鱼、金枪鱼和礁鲨','多处洞穴和拱门拥有清澈蓝色自然光'],route:'从珀斯搭乘航班抵达，岛上潜店根据风浪选择南北岸短船程潜点。',safety:'海墙深度下降极快，持续查看深度；鲸鲨活动遵守距离，岛上偏远需准备旅行与潜水保险。'},
  {id:'lord-howe',name:'豪勋爵岛',en:'Lord Howe Island · Australia',lat:-31.55,lng:159.08,depth:'5–40 m',species:'加拉帕戈斯鲨、海龟、隆头鱼',terrain:'潟湖、海山、珊瑚墙',level:'中级',rating:4,season:'9–5月',visibility:'15–40 m',temp:'18–26°C',desc:'世界最南端的堡礁之一处在热带与温带生态交界。潟湖浅礁适合轻松潜水，Ball’s Pyramid 的孤立海蚀柱则吸引大型鱼群和鲨鱼。',facts:['Ball’s Pyramid 是世界最高海蚀柱之一','热带珊瑚与温带鱼类在此共同出现','外海可见加拉帕戈斯鲨、国王鱼和成群杰克鱼'],route:'从悉尼或布里斯班乘小型航班；岛屿限制游客容量，住宿和潜水需提前预订。',safety:'外海海山航程与流况具有挑战；严格遵守世界遗产保护规则，不接触珊瑚和野生动物。'},
  {id:'solomon-islands',name:'所罗门群岛',en:'Solomon Islands · South Pacific',lat:-9.43,lng:159.96,depth:'3–45 m',species:'礁鲨、隆头鹦嘴鱼、豆丁海马',terrain:'二战沉船、珊瑚墙、洞穴',level:'中级',rating:4,season:'4–11月',visibility:'15–40 m',temp:'27–30°C',desc:'分散在南太平洋的岛链兼有原始珊瑚礁、二战沉船和著名光线洞穴。游客稀少，硬珊瑚、海扇与大型鱼群保留了强烈的荒野感。',facts:['Russell Islands 的 Leru Cut 以狭长光线洞穴闻名','Iron Bottom Sound 保存大量二战舰船与飞机','珊瑚墙常见礁鲨、海龟和隆头鹦嘴鱼'],route:'可从霍尼亚拉参加日船，也可用船宿覆盖 Russell、Florida 与更偏远岛屿。',safety:'偏远潜点医疗和通讯有限；沉船可能含未爆物与锋利金属，未经训练不可穿透。'},
  {id:'vanuatu',name:'瓦努阿图桑托岛',en:'Espiritu Santo · Vanuatu',lat:-15.38,lng:167.18,depth:'3–60 m',species:'儒艮、海龟、蝠鲼',terrain:'总统柯立芝号沉船、蓝洞、珊瑚礁',level:'进阶',rating:3,season:'4–11月',visibility:'15–40 m',temp:'25–29°C',desc:'桑托岛最著名的水下地标是巨大的总统柯立芝号沉船，船体从休闲深度延伸到技术潜水区。周边海草湾还有机会观察稀有儒艮。',facts:['总统柯立芝号全长约200米，可安排多条不同路线','Million Dollar Point 海底散布二战军用装备','海草床是儒艮和绿海龟的重要觅食地'],route:'以 Luganville 为基地，安排多日逐步探索沉船；儒艮观察需选择熟悉个体行为的向导。',safety:'大型沉船复杂且深，必须按资质选择路线；儒艮敏感，不可追逐、包围或阻挡其呼吸。'},
  {id:'new-caledonia',name:'新喀里多尼亚',en:'New Caledonia · South Pacific',lat:-22.45,lng:166.75,depth:'5–40 m',species:'儒艮、礁鲨、海龟、蝠鲼',terrain:'巨大潟湖、堡礁、水道',level:'全级别',rating:4,season:'9–12月 / 4–6月',visibility:'15–35 m',temp:'22–28°C',desc:'世界最大的潟湖系统之一环绕着主岛和外侧堡礁。浅海草床、红树林、蓝水水道与外礁墙构成完整生态梯度，大型动物和珊瑚多样性兼具。',facts:['潟湖是儒艮与绿海龟的重要栖息地','Dumbéa 水道常见礁鲨、鹰鳐和大型鱼群','Prony Bay 分布独特水下矿泉结构'],route:'努美阿周边日船最便利；想探索北部与 Loyalty Islands 需增加国内航班和住宿。',safety:'水道潜水受潮汐控制，偏远岛屿服务有限；儒艮活动区减速航行并保持观察距离。'},
  {id:'yap',name:'雅浦岛',en:'Yap · Micronesia',lat:9.54,lng:138.12,depth:'5–35 m',species:'蝠鲼、灰礁鲨、隆头鹦嘴鱼',terrain:'水道清洁站、珊瑚墙',level:'中级',rating:4,season:'12–4月',visibility:'15–35 m',temp:'27–30°C',desc:'雅浦以稳定的蝠鲼清洁站潜水闻名。狭窄水道中的潮汐将蝠鲼带到固定珊瑚头上方，潜水员可在低位安静观察个体排队接受清洁。',facts:['Mi’il Channel 是长期监测的蝠鲼清洁站','个体腹部斑纹可用于识别和科学记录','外礁墙可观察灰礁鲨与隆头鹦嘴鱼'],route:'住在 Colonia 附近，由当地潜店按潮汐安排每日两至三潜。',safety:'清洁站禁止越过规定观察线或产生过多气泡干扰；水道中保持低位并听从导潜。'},
  {id:'guam',name:'关岛',en:'Guam · Micronesia',lat:13.45,lng:144.65,depth:'3–40 m',species:'海龟、礁鲨、海豚',terrain:'蓝洞、珊瑚墙、沉船',level:'全级别',rating:4,season:'12–5月',visibility:'20–40 m',temp:'27–30°C',desc:'关岛兼有方便岸潜、深蓝洞穴和历史沉船。Apra Harbor 条件较平静，外海蓝洞与峭壁则为进阶潜水员提供更开阔的地形。',facts:['Blue Hole 的心形洞口是代表性地标','SMS Cormoran 与 Tokai Maru 两艘沉船在水下相邻','Gab Gab 浅礁常见海龟和大量珊瑚鱼'],route:'以 Tumon 或 Apra Harbor 为基地，岸潜与日船选择丰富，全年均有运营。',safety:'蓝洞出口和沉船深度较大，不可超越训练限制；军港部分水域受管制，跟随持证运营商。'},
  {id:'saipan',name:'塞班岛',en:'Saipan · Northern Mariana Islands',lat:15.19,lng:145.74,depth:'3–40 m',species:'鹰鳐、海龟、海豚',terrain:'海蚀洞、蓝洞、珊瑚礁',level:'全级别',rating:4,season:'3–8月',visibility:'25–45 m',temp:'27–30°C',desc:'马里亚纳群岛的透明海水环绕着石灰岩洞穴、白沙地和珊瑚坡。Grotto 从天然岩池进入开放海域，是西太平洋最具辨识度的洞穴潜点之一。',facts:['Grotto 三个水下出口通向深蓝外海','Lau Lau Beach 岸潜适合课程与海龟观察','Eagle Ray City 季节性聚集多只鹰鳐'],route:'岛上自驾便利，潜店提供岸潜与小艇潜水；Grotto 需携装备上下大量台阶。',safety:'Grotto 出入口可能有强浪涌且楼梯湿滑；鹰鳐观察保持低位，不从上方追赶。'},
  {id:'pohnpei',name:'波纳佩',en:'Pohnpei · Micronesia',lat:6.88,lng:158.2,depth:'5–40 m',species:'蝠鲼、灰礁鲨、梭鱼',terrain:'环礁水道、峭壁、潟湖',level:'进阶',rating:3,season:'10–4月',visibility:'15–35 m',temp:'27–30°C',desc:'高耸雨林岛屿被广阔堡礁包围，多个水道把远洋生物引入潟湖。潜点游客稀少，鲨鱼、蝠鲼和大型鱼群在强流中活动。',facts:['Palikir Pass 可见灰礁鲨与密集鱼群','Manta Road 是蝠鲼经过和清洁区域','外礁墙保留大面积海扇与硬珊瑚'],route:'以 Kolonia 为基地参加小艇潜水；潮汐决定水道潜水时间，雨季需预留天气弹性。',safety:'强流和外海升水要求熟练使用象拔；降雨可能影响潟湖能见度，听从当地潮汐判断。'},
  {id:'curacao',name:'库拉索岛',en:'Curaçao · Caribbean',lat:12.17,lng:-69.0,depth:'3–40 m',species:'海龟、鹰鳐、海马',terrain:'岸潜礁坡、沉船、珊瑚墙',level:'新手友好',rating:5,season:'全年',visibility:'20–35 m',temp:'26–29°C',desc:'背风南岸拥有数十处公路可达的岸潜点，珊瑚礁从浅湾逐渐下坡，导航清楚且海况稳定。彩色建筑与自由岸潜文化构成轻松的加勒比体验。',facts:['Tugboat 浅水沉船覆盖珊瑚并聚集鱼群','Playa Kalki 等西岸海湾适合自主岸潜','礁坡常见海龟、鹰鳐、海马与花园鳗'],route:'完成潜店检查潜后租车自驾探索西岸；也可参加船潜到达东端较少游客的礁区。',safety:'岸潜注意车辆物品安全、礁石和船道；始终使用潜伴制度并管理返程气量。'},
  {id:'utila',name:'乌蒂拉岛',en:'Utila · Honduras',lat:16.1,lng:-86.9,depth:'3–35 m',species:'鲸鲨、海龟、鹰鳐',terrain:'珊瑚墙、海山、沙地',level:'新手友好',rating:5,season:'3–5月 / 8–10月',visibility:'15–30 m',temp:'26–30°C',desc:'洪都拉斯湾群岛中氛围轻松的小岛，以经济的潜水课程和季节性鲸鲨相遇闻名。北岸深墙与南岸浅礁覆盖不同经验等级。',facts:['鲸鲨常在金枪鱼和海鸟活动的水面区域觅食','Black Hills 海山聚集杰克鱼和远洋访客','浅礁可见海龟、鹰鳐和加勒比珊瑚鱼'],route:'从拉塞瓦乘渡轮或搭小型飞机抵达；选择限制追逐和入水人数的鲸鲨运营商。',safety:'鲸鲨相遇多为浮潜且不可触摸；北岸船程和海况更具挑战，注意补水和晕浪。'},
  {id:'turneffe',name:'特内夫环礁',en:'Turneffe Atoll · Belize',lat:17.25,lng:-87.87,depth:'5–40 m',species:'海龟、鹰鳐、礁鲨、海豚',terrain:'环礁水道、红树林、珊瑚墙',level:'全级别',rating:5,season:'3–6月',visibility:'20–35 m',temp:'26–29°C',desc:'伯利兹近海最大的环礁由红树林、潟湖、海草床和外礁墙组成完整生态系统。Elbow 礁角的大型鱼群与外墙潜水最具代表性。',facts:['The Elbow 流起时聚集鲨鱼、鹰鳐和杰克鱼','红树林为幼年礁鱼和甲壳类提供育幼场','海草与浅礁常见海龟、海豚和鳐鱼'],route:'从伯利兹城参加日船航程较长，入住环礁度假村或船宿可减少往返并覆盖更多水道。',safety:'礁角水流需按潮汐安排；红树林和浅水区避免使用有害珊瑚的防晒产品。'},
  {id:'st-lucia',name:'圣卢西亚',en:'Saint Lucia · Caribbean',lat:13.83,lng:-61.06,depth:'3–35 m',species:'海龟、海马、鹰鳐',terrain:'火山尖峰、珊瑚墙、海湾',level:'全级别',rating:5,season:'12–5月',visibility:'15–30 m',temp:'26–29°C',desc:'皮通山火山尖峰不仅支配陆地天际线，也延伸为陡峭水下地形。Anse Chastanet 浅礁、Superman’s Flight 漂流墙和微距丰富的海湾可组合成多样行程。',facts:['Superman’s Flight 沿皮通山脚顺流经过软珊瑚墙','Anse Chastanet 可从沙滩直接进入珊瑚礁','海草与海绵区可寻找海马、海龟和海兔'],route:'住在 Soufrière 附近最接近核心潜点；北部度假区也可乘日船前往。',safety:'火山墙面深度下降快，持续检查深度；保护区内禁止触碰、喂食和采集海洋生物。'}
];

const speciesKnowledge={
  '鲸鲨':'鲸鲨是温和的滤食性大型鲨鱼，常随浮游生物、鱼卵和小型鱼群季节性出现；清晨、潮汐交换或生产力较高的水域相遇机会更大。',
  '蝠鲼':'蝠鲼常在海山、水道和固定清洁站盘旋，让小型清洁鱼移除寄生物；也会在浮游生物密集时张口滤食。',
  '锤头鲨':'锤头鲨偏好远海海山、岛屿边缘和深水清洁站，部分地点可形成大型群游；通常在蓝水边缘观察，接近距离受温度与水流影响。',
  '虎鲨':'虎鲨是大型机会主义捕食者，活动范围广，常沿沙地、礁坡和海龟活动区巡游；观察应保持稳定站位并避免突然追近。',
  '礁鲨':'白鳍、黑鳍与灰礁鲨常沿礁角和水道巡游。白鳍鲨会在洞穴或沙地休息，灰礁鲨更偏好流起时的外礁边缘。',
  '长尾鲨':'长尾鲨以极长尾鳍击晕猎物，通常从深水上升到特定清洁站；清晨、安静和保持距离有助于观察其自然行为。',
  '远洋白鳍鲨':'远洋白鳍鲨是好奇且自信的开放海域鲨鱼，常在远海礁体、船只和深蓝水域附近巡游，需要严格执行团队站位。',
  '海龟':'绿海龟多在海草床觅食，玳瑁偏爱在珊瑚礁啃食海绵；两者都需要定期上浮呼吸，观察时不可阻挡上升路线。',
  '玳瑁':'玳瑁拥有尖窄嘴部，常在珊瑚缝隙取食海绵，是健康热带礁区的重要成员。',
  '海豚':'宽吻海豚、飞旋海豚等具有复杂社会行为，可能结群巡游、捕猎或主动接近；互动必须由动物自主发起。',
  '座头鲸':'座头鲸在繁殖季迁徙到温暖海域，潜水时常先听到低频歌声；母子鲸尤其需要更大的观察距离。',
  '海狮':'海狮好奇、敏捷，常在浅水模仿潜水员翻转或轻咬气泡；成年雄性具有领地性，应留意其警告姿态。',
  '海狗':'海狗会在海带林和岩岸附近快速游动，幼体尤其好奇；避免触摸，以免改变野生行为。',
  '儒艮':'儒艮依赖健康海草床，以海草为食，种群密度低且容易受船只与噪音干扰，偶遇时应保持安静和较远距离。',
  '海马':'海马依靠卷曲尾部固定在海草、海扇或碎屑上，游泳能力弱且伪装出色；微距观察不可移动其附着物。',
  '豆丁海马':'豆丁海马通常不足两厘米，颜色和突起与宿主海扇高度一致；强光和反复闪光会造成压力。',
  '海蛞蝓':'海蛞蝓种类繁多，颜色常用于警戒或伪装，不同物种专食海绵、水螅或苔藓虫，是微距物种搜索的重要指标。',
  '章鱼':'章鱼具备出色变色、拟态和问题解决能力，多在岩缝、椰壳或沙地活动；夜潜更容易观察捕食和移动。',
  '拟态章鱼':'拟态章鱼可改变颜色、姿势与运动方式，模拟海蛇、狮子鱼等有毒动物，主要生活在开阔沙泥底。',
  '蓝环章鱼':'蓝环章鱼体型小且毒性极强，受威胁时蓝环会变得鲜明；只能远距离观察，绝不可触碰。',
  '躄鱼':'躄鱼使用胸鳍在底部“行走”，头部诱饵用于吸引猎物；常伪装成海绵、岩石或藻类。',
  '鬼龙':'鬼龙身体细长并模仿海草、海百合或羽毛状生物，常成对出现，是海草床和珊瑚坡的微距目标。',
  '海蛇':'海蛇常沿珊瑚墙和沙地搜索鳗类与小鱼，虽有毒但通常温和，会定期上浮呼吸。',
  '鹰鳐':'鹰鳐通常沿沙地、礁坡和蓝水边缘优雅巡游，以贝类和甲壳类为食，受惊时会迅速远离。',
  '黄貂鱼':'黄貂鱼常半埋在浅沙地，以小型底栖动物为食；尾刺是防御结构，观察时不要从上方围堵。',
  '梭鱼':'梭鱼会在流起的礁角形成旋转或柱状鱼群，银色身体反射光线；群体形态随捕食压力与水流改变。',
  '杰克鱼':'杰克鱼常形成紧密鱼球以降低被捕食风险，在礁角、沉船和海山附近最容易观察。',
  '沙丁鱼':'沙丁鱼依靠同步转向形成巨大饵球，受到海豚、鲨鱼或金枪鱼攻击时会快速收缩、分裂与重组。',
  '石斑鱼':'石斑鱼多在礁洞与岩壁附近伏击猎物，部分种类会在特定月相大规模聚集产卵。',
  '隆头鱼':'大型隆头鱼包括苏眉鱼，具有明显个体识别能力，常在清洁站和礁坡活动；成熟个体生长缓慢。',
  '苏眉鱼':'苏眉鱼体型巨大、性情温和，常沿礁坡和清洁站活动，是受保护且生长缓慢的隆头鱼。',
  '海鳗':'海鳗白天常从岩缝探头并张口泵水呼吸，夜间离巢捕食；清洁虾有时会为其清理口腔。',
  '狼鳗':'狼鳗是北太平洋温带鱼类，成对居住在岩洞，以强壮颌部咬碎海胆和贝类。',
  '巨型太平洋章鱼':'巨型太平洋章鱼生活在冷水岩礁，体型可观且善于变色；洞口常散落被取食后的蟹壳。',
  '企鹅':'企鹅在水下利用翅膀高速“飞行”，常从冰缘或岩岸集体入水，动作迅速且不宜追逐。',
  '豹海豹':'豹海豹是南极大型捕食者，可能表现出好奇或领地行为，必须由专业向导评估互动距离。',
  '翻车鱼':'翻车鱼会从深水上升到较浅的清洁站接受蝴蝶鱼等移除寄生物，冷水上升流季节相遇率较高；追逐会让其迅速返回深水。',
  '隆头鹦嘴鱼':'隆头鹦嘴鱼体型巨大，黎明常成群离开夜间休息区，以珊瑚表面藻类为食，并通过排出细沙参与礁区物质循环。',
  '蝎子鱼':'蝎子鱼善于伪装在珊瑚、海绵和沉船表面，依靠伏击捕食小鱼；背鳍棘具有毒性，观察时不可触碰或跪底。',
  '水母':'水母以浮游生物为食并随水体移动，封闭海湖中的部分种群因缺少捕食者而弱化刺细胞，但仍应避免抓握。',
  '珊瑚':'造礁珊瑚由共生虫黄藻提供能量，软珊瑚则依靠水流输送食物；覆盖率与结构复杂度直接影响礁鱼多样性。'
};
function speciesProfile(s){
  const notes=[];
  Object.entries(speciesKnowledge).forEach(([key,text])=>{if(s.species.includes(key)&&!notes.includes(text))notes.push(text)});
  if(!notes.length)notes.push(`${s.species}是该区域最具代表性的观察对象，其出现会随水温、潮汐、食物和繁殖周期变化。`);
  return notes.slice(0,4).join(' ');
}

const search=document.querySelector('#search'),results=document.querySelector('#results'),drawer=document.querySelector('#drawer'),detail=document.querySelector('#detail');
const map=L.map('map',{zoomControl:true,minZoom:2,maxZoom:15,worldCopyJump:true}).setView([14,15],2);
L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19,attribution:'© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'}).addTo(map);
const icon=L.divIcon({className:'dive-marker',html:'<span class="dive-star">✦</span>',iconSize:[30,30],iconAnchor:[15,15]});
const markerById=new Map();
function stars(n){return '★'.repeat(n)+'☆'.repeat(5-n)}
function popup(s){return `<div class="tip-top"><div><div class="tip-kicker">${s.en}</div><button class="tip-title" data-open="${s.id}">${s.name} ↗</button></div><span class="depth">${s.depth}</span></div><div class="tip-grid"><div class="tip-item"><label>特色物种</label><span>${s.species}</span></div><div class="tip-item"><label>地貌特点</label><span>${s.terrain}</span></div><div class="tip-item"><label>难度</label><span>${s.level}</span></div><div class="tip-item"><label>新手推荐</label><span class="rating">${stars(s.rating)}</span></div></div>`}
sites.forEach(s=>{const m=L.marker([s.lat,s.lng],{icon,title:s.name,alt:s.name}).addTo(map);m.bindTooltip(popup(s),{direction:'top',offset:[0,-12],opacity:1,className:'dive-tooltip',interactive:true});m.on('click',()=>openDetail(s));markerById.set(s.id,m)});

function openDetail(s){
  markerById.forEach((m,id)=>m.getElement()?.classList.toggle('is-active',id===s.id));
  detail.innerHTML=`<div class="detail-kicker">${s.en}</div><h2>${s.name}</h2><p class="detail-lead">${s.desc}</p><div class="stats"><div class="stat"><label>推荐深度</label><strong>${s.depth}</strong></div><div class="stat"><label>难度</label><strong>${s.level}</strong></div><div class="stat"><label>新手指数</label><strong>${s.rating} / 5</strong></div></div><div class="detail-kicker">代表物种与生态行为</div><p class="detail-lead"><b>${s.species}</b><br>${speciesProfile(s)}</p><div class="detail-kicker">水下环境</div><ul class="feature-list"><li><b>地貌</b><span>${s.terrain}</span></li><li><b>视野</b><span>能见度通常 ${s.visibility}，水温约 ${s.temp}</span></li>${s.facts.map((x,i)=>`<li><b>0${i+1}</b><span>${x}</span></li>`).join('')}</ul><div class="detail-kicker">如何体验</div><p class="detail-lead">${s.route}</p><div class="season"><b>最佳季节 · </b>${s.season}<br><br><b>安全与经验 · </b>${s.safety}<br><br><small>海况、能见度及动物出现均会随季节变化，预订前请向当地持证潜店核实实时条件。</small></div>`;
  drawer.classList.add('open');drawer.setAttribute('aria-hidden','false');document.querySelector('#backdrop').classList.add('show');
}
function closeDetail(){drawer.classList.remove('open');drawer.setAttribute('aria-hidden','true');document.querySelector('#backdrop').classList.remove('show');markerById.forEach(m=>m.getElement()?.classList.remove('is-active'))}
document.querySelector('#close').onclick=closeDetail;document.querySelector('#backdrop').onclick=closeDetail;
document.addEventListener('click',e=>{const btn=e.target.closest('[data-open]');if(btn){const s=sites.find(x=>x.id===btn.dataset.open);if(s)openDetail(s)}if(!e.target.closest('.search-wrap'))results.classList.remove('show')});
document.addEventListener('keydown',e=>{if(e.key==='Escape'){closeDetail();results.classList.remove('show')}if(e.key==='/'&&document.activeElement!==search){e.preventDefault();search.focus()}});
function doSearch(){
  const q=search.value.trim().toLowerCase();const found=q?sites.filter(s=>(Object.values(s).join(' ')+' '+speciesProfile(s)).toLowerCase().includes(q)):sites;
  document.querySelector('#count').textContent=String(found.length).padStart(2,'0');
  markerById.forEach((m,id)=>m.setOpacity(found.some(s=>s.id===id)?1:.16));
  if(!q){results.classList.remove('show');return}
  results.innerHTML=found.length?found.map(s=>`<button class="result" data-id="${s.id}"><span><strong>${s.name}</strong><small>${s.species} · ${s.terrain}</small></span><span>${s.level} ↗</span></button>`).join(''):'<div class="no-result">没有找到匹配潜点，试试“海龟”“沉船”或“新手”</div>';
  results.classList.add('show');results.querySelectorAll('.result').forEach(b=>b.onclick=()=>{const s=sites.find(x=>x.id===b.dataset.id);map.flyTo([s.lat,s.lng],5,{duration:1.2});openDetail(s);results.classList.remove('show')});
}
search.addEventListener('input',doSearch);search.addEventListener('focus',()=>{if(search.value)doSearch()});
